# ═══════════════════════════════════════════════════════════════════════
# TOOLTIP HELPER (1 sn gecikmeli hover ipucu)
# ═══════════════════════════════════════════════════════════════════════
class _Tooltip:
    """Widget üzerinde 1 saniye bekleyince çıkan açıklama balonu."""

    def __init__(self, widget, text: str, delay_ms: int = 1000):
        self.widget = widget
        self.text = text
        self.delay = delay_ms
        self._tip = None
        self._after_id = None
        widget.bind("<Enter>", self._enter, add="+")
        widget.bind("<Leave>", self._leave, add="+")
        widget.bind("<ButtonPress>", self._leave, add="+")

    def _enter(self, _event=None):
        self._cancel()
        self._after_id = self.widget.after(self.delay, self._show)

    def _leave(self, _event=None):
        self._cancel()
        if self._tip is not None:
            try:
                self._tip.destroy()
            except Exception:
                pass
            self._tip = None

    def _cancel(self):
        if self._after_id:
            try:
                self.widget.after_cancel(self._after_id)
            except Exception:
                pass
            self._after_id = None

    def _show(self):
        if self._tip is not None:
            return
        try:
            x = self.widget.winfo_rootx() + 12
            y = self.widget.winfo_rooty() + self.widget.winfo_height() + 4
        except Exception:
            return
        self._tip = tk.Toplevel(self.widget)
        self._tip.wm_overrideredirect(True)
        self._tip.wm_geometry(f"+{x}+{y}")
        try:
            self._tip.attributes("-topmost", True)
        except Exception:
            pass
        tk.Label(self._tip, text=self.text,
                  bg="#FFFDE7", fg="#37474F",
                  relief="solid", bd=1, padx=8, pady=4,
                  font=("Segoe UI", 9), wraplength=340, justify="left"
                  ).pack()


def _tt(widget, text: str):
    """Kısa kısayol — widget'a tooltip ekler ve widget'ı geri döndürür."""
    _Tooltip(widget, text)
    return widget


# ═══════════════════════════════════════════════════════════════════════
# ÇOKLU SEÇİM DROPDOWN
# ═══════════════════════════════════════════════════════════════════════
class MultiSelectDropdown(tk.Frame):
    """Checkbox'lı popup açan çoklu seçim dropdown widget'ı.

    Bir butona benzer; tıklandığında her seçeneğin yanında onay kutusu olan
    popup açar. Seçili öğe sayısına göre buton etiketi:
      - '<deger>  ▼'                (tek seçim)
      - '<deger>  +N  ▼'            (çoklu seçim)
    on_change(secilenler) callback'i değişimlerde tetiklenir.
    'Tümü' seçeneği özel: işaretliyse diğerleri pasif görünür ve tek başına
    seçili sayılır.
    """

    TUMU_ETIKETI = "Tümü"

    def __init__(self, parent, ogeler, varsayilan=None, on_change=None,
                 baslik="Seçim", **btn_kwargs):
        try:
            pbg = parent.cget("bg")
        except Exception:
            pbg = None
        if pbg:
            super().__init__(parent, bg=pbg)
        else:
            super().__init__(parent)

        self.ogeler = list(ogeler)
        self.on_change = on_change
        self.baslik = baslik

        if varsayilan is None:
            self.secili = [self.ogeler[0]] if self.ogeler else []
        elif isinstance(varsayilan, (list, tuple, set)):
            self.secili = [d for d in self.ogeler if d in varsayilan]
            if not self.secili and self.ogeler:
                self.secili = [self.ogeler[0]]
        else:
            self.secili = ([varsayilan] if varsayilan in self.ogeler
                           else ([self.ogeler[0]] if self.ogeler else []))

        defaults = dict(font=("Segoe UI", 9), relief="sunken",
                        bg="white", fg="black", bd=1, cursor="hand2")
        defaults.update(btn_kwargs)
        self._buton = tk.Button(self, text=self._etiket(),
                                 command=self._popup_toggle, **defaults)
        self._buton.pack(fill="both", expand=True)
        self._popup = None
        self._popup_varlari = {}
        self._global_click_funcid = None

    def _etiket(self):
        if not self.secili:
            return f"{self.baslik} seç... ▼"
        # 'Tümü' seçeneği özel: sadece o gösterilir
        if self.TUMU_ETIKETI in self.secili:
            return f"{self.TUMU_ETIKETI}  ▼"
        if len(self.secili) == 1:
            return f"{self.secili[0]}  ▼"
        return f"{self.secili[0]}  +{len(self.secili) - 1}  ▼"

    def _popup_toggle(self):
        if self._popup is not None and self._popup.winfo_exists():
            self._popup_kapat()
            return
        self._popup_ac()

    def _popup_ac(self):
        """Çoklu seçim popup'ı.

        Win10'da maximized (zoomed) parent + wm_overrideredirect Tk'nin
        popup'ı render etmeyip 'kilitlenmiş gibi' davranmasına yol açabiliyor.
        Bu yüzden popup normal title bar'lı bir Toplevel olarak açılır;
        transient ile parent'a bağlanır ve grab_set ile modal yapılır.
        """
        root = self.winfo_toplevel()
        popup = tk.Toplevel(root)
        popup.title(f"{self.baslik} (çoklu seçim)")
        popup.configure(bg="#FAFAFA")
        popup.resizable(False, False)
        try:
            popup.transient(root)
        except Exception:
            pass

        tk.Label(popup, text=f"☑ {self.baslik} — birden fazla seçebilirsiniz",
                 font=("Segoe UI", 9, "bold"),
                 fg="#FFFFFF", bg="#1976D2", anchor="w",
                 padx=6, pady=2).pack(fill="x")

        cb_frame = tk.Frame(popup, bg="#FAFAFA")
        cb_frame.pack(fill="both", expand=True, padx=2, pady=2)

        self._popup_varlari = {}
        for d in self.ogeler:
            var = tk.BooleanVar(value=(d in self.secili))
            self._popup_varlari[d] = var
            tk.Checkbutton(cb_frame, text=d, variable=var, anchor="w",
                           bg="#FAFAFA", fg="#212121",
                           selectcolor="#FFFFFF",
                           activebackground="#E3F2FD",
                           activeforeground="#0D47A1",
                           font=("Segoe UI", 9), padx=4, pady=0,
                           command=lambda dd=d, vv=var: self._toggle(dd, vv)
                           ).pack(fill="x", padx=0, pady=0, anchor="w")

        alt = tk.Frame(popup, bg="#E0E0E0")
        alt.pack(fill="x")
        tk.Button(alt, text="Tümünü Seç", font=("Segoe UI", 8),
                  fg="white", bg="#1565C0", activebackground="#0D47A1",
                  bd=0, padx=8, pady=2, command=self._tumunu_sec
                  ).pack(side="left", padx=3, pady=2)
        tk.Button(alt, text="Temizle", font=("Segoe UI", 8),
                  fg="white", bg="#6A1B9A", activebackground="#4A148C",
                  bd=0, padx=8, pady=2, command=self._temizle
                  ).pack(side="left", padx=3, pady=2)
        tk.Button(alt, text="✓ Tamam", font=("Segoe UI", 8, "bold"),
                  fg="white", bg="#2E7D32", activebackground="#1B5E20",
                  bd=0, padx=12, pady=2, command=self._popup_kapat
                  ).pack(side="right", padx=3, pady=2)

        popup.update_idletasks()
        # Popup'ı butonun altına konumlandır
        try:
            x = self._buton.winfo_rootx()
            y = self._buton.winfo_rooty() + self._buton.winfo_height()
            sw = popup.winfo_screenwidth()
            sh = popup.winfo_screenheight()
            pw = popup.winfo_reqwidth()
            ph = popup.winfo_reqheight()
            if x + pw > sw:
                x = max(0, sw - pw - 4)
            if y + ph > sh:
                y = max(0, self._buton.winfo_rooty() - ph)
            popup.geometry(f"+{x}+{y}")
        except Exception:
            pass

        self._popup = popup
        popup.protocol("WM_DELETE_WINDOW", self._popup_kapat)
        popup.bind("<Escape>", lambda e: self._popup_kapat())
        try:
            popup.lift()
            popup.focus_force()
        except Exception:
            pass

    def _global_click_bind(self):
        try:
            self._global_click_funcid = self.winfo_toplevel().bind(
                "<Button-1>", self._on_global_click, add="+"
            )
        except Exception:
            self._global_click_funcid = None

    def _on_global_click(self, event):
        if self._popup is None:
            return
        try:
            x, y = event.x_root, event.y_root
            px, py = self._popup.winfo_rootx(), self._popup.winfo_rooty()
            pw, ph = self._popup.winfo_width(), self._popup.winfo_height()
            if px <= x <= px + pw and py <= y <= py + ph:
                return
            bx, by = self._buton.winfo_rootx(), self._buton.winfo_rooty()
            bw, bh = self._buton.winfo_width(), self._buton.winfo_height()
            if bx <= x <= bx + bw and by <= y <= by + bh:
                return
        except Exception:
            pass
        self._popup_kapat()

    def _popup_kapat(self, *args):
        if self._global_click_funcid:
            try:
                self.winfo_toplevel().unbind("<Button-1>", self._global_click_funcid)
            except Exception:
                pass
            self._global_click_funcid = None
        if self._popup is not None:
            try:
                if self._popup.winfo_exists():
                    self._popup.destroy()
            except Exception:
                pass
            self._popup = None
        self._popup_varlari = {}

    def _toggle(self, oge, var):
        if var.get():
            # 'Tümü' işaretlendi → diğerlerini temizle
            if oge == self.TUMU_ETIKETI:
                self.secili = [self.TUMU_ETIKETI]
                for d, v in self._popup_varlari.items():
                    v.set(d == self.TUMU_ETIKETI)
            else:
                # Tümü işaretliydi ise kaldır (artık özel seçim var)
                if self.TUMU_ETIKETI in self.secili:
                    self.secili = [d for d in self.secili
                                   if d != self.TUMU_ETIKETI]
                    if self.TUMU_ETIKETI in self._popup_varlari:
                        self._popup_varlari[self.TUMU_ETIKETI].set(False)
                if oge not in self.secili:
                    self.secili = [d for d in self.ogeler
                                   if d in self.secili or d == oge]
        else:
            self.secili = [d for d in self.secili if d != oge]
        if not self.secili and self.ogeler:
            self.secili = [oge]
            var.set(True)
        self._buton.config(text=self._etiket())
        if self.on_change:
            try:
                self.on_change(list(self.secili))
            except Exception:
                pass

    def _tumunu_sec(self):
        self.secili = list(self.ogeler)
        for var in self._popup_varlari.values():
            var.set(True)
        self._buton.config(text=self._etiket())
        if self.on_change:
            try:
                self.on_change(list(self.secili))
            except Exception:
                pass

    def _temizle(self):
        ilk = self.ogeler[0] if self.ogeler else None
        self.secili = [ilk] if ilk else []
        for d, var in self._popup_varlari.items():
            var.set(d == ilk)
        self._buton.config(text=self._etiket())
        if self.on_change:
            try:
                self.on_change(list(self.secili))
            except Exception:
                pass

    def get_secilenler(self):
        return list(self.secili)

    def set_secilenler(self, ogeler):
        valid = [d for d in self.ogeler if d in ogeler]
        if not valid and self.ogeler:
            valid = [self.ogeler[0]]
        self.secili = valid
        self._buton.config(text=self._etiket())

    def set_ogeler(self, ogeler, varsayilan=None):
        """Öğeleri yeniden ayarla (örn. yıl listesi DB'den yüklendi)."""
        self.ogeler = list(ogeler)
        if varsayilan is None:
            self.secili = [self.ogeler[0]] if self.ogeler else []
        elif isinstance(varsayilan, (list, tuple, set)):
            self.secili = [d for d in self.ogeler if d in varsayilan]
            if not self.secili and self.ogeler:
                self.secili = [self.ogeler[0]]
        else:
            self.secili = ([varsayilan] if varsayilan in self.ogeler
                           else ([self.ogeler[0]] if self.ogeler else []))
        self._buton.config(text=self._etiket())


# ═══════════════════════════════════════════════════════════════════════
# AI KONTROL — İLERLEME DIALOG
# ═══════════════════════════════════════════════════════════════════════
class AIKontrolIlerleme:
    """🤖 AI Kontrol sırasında aşama/sayaç/süreyi gösteren modal pencere.

    Worker thread'ten thread-safe güncelleme için: tüm setter'lar
    `self.root.after(0, ...)` üzerinden çağrılmalı.

    Aşamalar:
        VERI : 📦 Veriler toplanıyor (Botanik DB + geçmiş rapor)
        AI   : 🤖 Claude değerlendiriyor (API/subprocess çağrısı)
        KAYIT: 💾 Sonuç kaydediliyor (yerel DB)
    """
    ASAMA_VERI = "VERI"
    ASAMA_AI = "AI"
    ASAMA_KAYIT = "KAYIT"

    _ASAMA_LABEL = {
        ASAMA_VERI:  "📦 Veriler toplanıyor (Botanik DB + geçmiş raporlar)",
        ASAMA_AI:    "🤖 Claude değerlendiriyor (model sorgulanıyor)",
        ASAMA_KAYIT: "💾 Sonuç işleniyor ve kaydediliyor",
    }
    _ASAMA_SIRASI = (ASAMA_VERI, ASAMA_AI, ASAMA_KAYIT)

    def __init__(self, parent: tk.Tk, toplam: int):
        import time
        self.parent = parent
        self.root = parent
        self.toplam = max(1, int(toplam))
        self.mevcut_no = 0
        self.mevcut_ilac = ""
        self.iptal_istendi = False
        self._t0 = time.time()
        self._t_recete = time.time()
        self._asama_durumlari = {a: "bekliyor" for a in self._ASAMA_SIRASI}
        self._kapali = False
        self._tamamlandi_flag = False
        self._timer_job = None
        self._sayac_etiket = {}        # AI çağrısı sayaçları (success/fail)
        self._sayac_etiket = {
            "UYGUN": 0, "UYGUN_DEGIL": 0, "SUPHELI": 0,
            "KONTROL_EDILEMEDI": 0, "HATA": 0,
        }
        self._yapi_kur()
        self._timer_baslat()

    # ── Pencere yapısı ───────────────────────────────────────────────
    def _yapi_kur(self):
        w = tk.Toplevel(self.parent)
        self.win = w
        w.title("🤖 AI Kontrol İşleniyor")
        w.transient(self.parent)
        try:
            w.grab_set()
        except Exception:
            pass
        w.resizable(True, True)
        w.protocol("WM_DELETE_WINDOW", self._iptal_tikla)
        w.configure(bg="#FAFAFA")

        # Konum: ekran merkezi (büyük pencere için ekran taşmasını engelle)
        try:
            self.parent.update_idletasks()
            sw = self.parent.winfo_screenwidth()
            sh = self.parent.winfo_screenheight()
            ww, wh = 980, 720
            if wh > sh - 60:
                wh = sh - 60
            if ww > sw - 40:
                ww = sw - 40
            x = max(0, (sw - ww) // 2)
            y = max(0, (sh - wh) // 2 - 20)
            w.geometry(f"{ww}x{wh}+{x}+{y}")
            w.minsize(620, 540)
        except Exception:
            w.geometry("980x720")

        # ── Başlık ──
        baslik = tk.Frame(w, bg="#01579B", height=44)
        baslik.pack(fill="x")
        baslik.pack_propagate(False)
        tk.Label(
            baslik, text="🤖 AI Kontrol Çalışıyor",
            font=("Segoe UI", 13, "bold"),
            bg="#01579B", fg="white",
        ).pack(side="left", padx=14, pady=8)
        self.lbl_sayac = tk.Label(
            baslik, text=f"0 / {self.toplam}",
            font=("Segoe UI", 11, "bold"),
            bg="#01579B", fg="#E1F5FE",
        )
        self.lbl_sayac.pack(side="right", padx=14, pady=8)

        # ── Aktif reçete-ilaç ──
        bilgi = tk.Frame(w, bg="#FAFAFA")
        bilgi.pack(fill="x", padx=14, pady=(10, 4))
        tk.Label(
            bilgi, text="İşlenen ilaç:",
            font=("Segoe UI", 9), bg="#FAFAFA", fg="#666",
        ).pack(side="left")
        self.lbl_ilac = tk.Label(
            bilgi, text="—",
            font=("Segoe UI", 10, "bold"),
            bg="#FAFAFA", fg="#01579B",
            anchor="w",
        )
        self.lbl_ilac.pack(side="left", padx=(8, 0), fill="x", expand=True)

        # ── Aşama listesi ──
        asama_frame = tk.LabelFrame(
            w, text=" Aşamalar ",
            font=("Segoe UI", 9, "bold"),
            bg="#FAFAFA", fg="#333",
            padx=12, pady=8,
        )
        asama_frame.pack(fill="x", padx=14, pady=8)

        self._asama_widgetlari = {}
        for asama in self._ASAMA_SIRASI:
            satir = tk.Frame(asama_frame, bg="#FAFAFA")
            satir.pack(fill="x", pady=3)
            ikon = tk.Label(
                satir, text="⚪", font=("Segoe UI", 11),
                bg="#FAFAFA", width=2,
            )
            ikon.pack(side="left")
            metin = tk.Label(
                satir, text=self._ASAMA_LABEL[asama],
                font=("Segoe UI", 10),
                bg="#FAFAFA", fg="#888",
                anchor="w",
            )
            metin.pack(side="left", fill="x", expand=True)
            sure = tk.Label(
                satir, text="", font=("Segoe UI", 9),
                bg="#FAFAFA", fg="#999", width=8,
            )
            sure.pack(side="right")
            self._asama_widgetlari[asama] = (ikon, metin, sure, [None])
            # 4. eleman: aşama başlangıç zamanı [mutable]

        # ── İlerleme çubuğu (indeterminate) ──
        pb_frame = tk.Frame(w, bg="#FAFAFA")
        pb_frame.pack(fill="x", padx=14, pady=(4, 4))
        self.pb = ttk.Progressbar(pb_frame, mode="indeterminate")
        self.pb.pack(fill="x")
        try:
            self.pb.start(80)
        except Exception:
            pass

        # ── Süre + ara özet ──
        alt = tk.Frame(w, bg="#FAFAFA")
        alt.pack(fill="x", padx=14, pady=(2, 6))
        self.lbl_sure = tk.Label(
            alt, text="Geçen süre: 0 sn",
            font=("Segoe UI", 9), bg="#FAFAFA", fg="#555",
        )
        self.lbl_sure.pack(side="left")
        self.lbl_ozet = tk.Label(
            alt, text="",
            font=("Segoe UI", 9), bg="#FAFAFA", fg="#2E7D32",
        )
        self.lbl_ozet.pack(side="right")

        # ── 💬 Canlı AI yorum paneli ──
        yorum_frame = tk.LabelFrame(
            w, text=" 💬 AI Yorumu (canlı — her reçete bittikçe eklenir) ",
            font=("Segoe UI", 9, "bold"),
            bg="#FAFAFA", fg="#01579B",
            padx=8, pady=6,
        )
        yorum_frame.pack(fill="both", expand=True, padx=14, pady=(4, 4))

        yorum_ic = tk.Frame(yorum_frame, bg="#FAFAFA")
        yorum_ic.pack(fill="both", expand=True)
        vsb_y = ttk.Scrollbar(yorum_ic, orient="vertical")
        vsb_y.pack(side="right", fill="y")
        self.txt_yorum = tk.Text(
            yorum_ic, wrap="word",
            font=("Segoe UI", 10),
            bg="#FFFFFF", fg="#212121",
            padx=10, pady=8,
            height=12,
            yscrollcommand=vsb_y.set,
            state="disabled",
        )
        self.txt_yorum.pack(side="left", fill="both", expand=True)
        vsb_y.config(command=self.txt_yorum.yview)

        # Stil tagları
        self.txt_yorum.tag_configure(
            "h_recete", font=("Segoe UI", 11, "bold"),
            foreground="#FFFFFF", background="#01579B",
            lmargin1=4, lmargin2=4, spacing1=6, spacing3=4,
        )
        self.txt_yorum.tag_configure(
            "h_sonuc_uygun", font=("Segoe UI", 10, "bold"), foreground="#2E7D32")
        self.txt_yorum.tag_configure(
            "h_sonuc_yok", font=("Segoe UI", 10, "bold"), foreground="#C62828")
        self.txt_yorum.tag_configure(
            "h_sonuc_supheli", font=("Segoe UI", 10, "bold"), foreground="#EF6C00")
        self.txt_yorum.tag_configure(
            "h_alt", font=("Segoe UI", 9, "bold"), foreground="#0277BD",
            spacing1=6, spacing3=2,
        )
        self.txt_yorum.tag_configure(
            "klinik", font=("Segoe UI", 10), foreground="#212121",
            lmargin1=8, lmargin2=8, spacing1=2, spacing3=2,
        )
        self.txt_yorum.tag_configure(
            "var", foreground="#2E7D32")
        self.txt_yorum.tag_configure(
            "yok", foreground="#C62828")
        self.txt_yorum.tag_configure(
            "ke", foreground="#EF6C00")

        # ── İptal butonu ──
        btn_frame = tk.Frame(w, bg="#FAFAFA")
        btn_frame.pack(fill="x", padx=14, pady=(2, 10))
        self.btn_iptal = tk.Button(
            btn_frame, text="✖ İptal Et (bu reçete bitince durur)",
            font=("Segoe UI", 10),
            bg="#FFEBEE", fg="#B71C1C", activebackground="#FFCDD2",
            relief="flat", bd=1, cursor="hand2",
            command=self._iptal_tikla,
        )
        self.btn_iptal.pack(fill="x")

    # ── Timer (geçen süre) ──────────────────────────────────────────
    def _timer_baslat(self):
        import time
        if self._kapali:
            return
        elapsed = int(time.time() - self._t0)
        try:
            self.lbl_sure.config(
                text=f"Geçen süre: {elapsed // 60}dk {elapsed % 60:02d}sn"
                     if elapsed >= 60 else f"Geçen süre: {elapsed} sn"
            )
        except Exception:
            return
        # Aktif aşamanın süresini güncelle
        for asama, (ikon, metin, sure, t0_ref) in self._asama_widgetlari.items():
            if self._asama_durumlari.get(asama) == "calisiyor" and t0_ref[0]:
                a_el = int(time.time() - t0_ref[0])
                try:
                    sure.config(text=f"{a_el}s")
                except Exception:
                    pass
        self._timer_job = self.parent.after(500, self._timer_baslat)

    # ── Public API (worker thread'ten root.after ile çağrılır) ──────
    def recete_basla(self, no: int, ilac_adi: str):
        """Yeni bir reçete-ilaç işlemeye başlandı."""
        import time
        if self._kapali:
            return
        self.mevcut_no = no
        self.mevcut_ilac = ilac_adi or "—"
        self._t_recete = time.time()
        try:
            self.lbl_sayac.config(text=f"{no} / {self.toplam}")
            self.lbl_ilac.config(text=self.mevcut_ilac[:60])
        except Exception:
            return
        # Aşamaları sıfırla
        for asama in self._ASAMA_SIRASI:
            self._asama_durumlari[asama] = "bekliyor"
            ikon, metin, sure, t0_ref = self._asama_widgetlari[asama]
            try:
                ikon.config(text="⚪")
                metin.config(fg="#888")
                sure.config(text="")
            except Exception:
                pass
            t0_ref[0] = None

    def asama_basla(self, asama: str):
        """Belirtilen aşamayı 'çalışıyor' durumuna al."""
        import time
        if self._kapali or asama not in self._ASAMA_SIRASI:
            return
        self._asama_durumlari[asama] = "calisiyor"
        ikon, metin, sure, t0_ref = self._asama_widgetlari[asama]
        t0_ref[0] = time.time()
        try:
            ikon.config(text="⏳")
            metin.config(fg="#01579B", font=("Segoe UI", 10, "bold"))
        except Exception:
            pass

    def asama_bitir(self, asama: str, basarili: bool = True):
        """Belirtilen aşamayı 'tamam' veya 'hata' durumuna al."""
        import time
        if self._kapali or asama not in self._ASAMA_SIRASI:
            return
        ikon, metin, sure, t0_ref = self._asama_widgetlari[asama]
        if t0_ref[0]:
            elapsed = int(time.time() - t0_ref[0])
            try:
                sure.config(text=f"{elapsed}s")
            except Exception:
                pass
        self._asama_durumlari[asama] = "tamam" if basarili else "hata"
        try:
            if basarili:
                ikon.config(text="✓")
                metin.config(fg="#2E7D32", font=("Segoe UI", 10))
            else:
                ikon.config(text="✗")
                metin.config(fg="#C62828", font=("Segoe UI", 10))
        except Exception:
            pass

    def sonuc_kaydet(self, sonuc_etiketi: str):
        """Bir reçetenin sonuç sayaç güncellemesi."""
        if self._kapali:
            return
        key = sonuc_etiketi if sonuc_etiketi in self._sayac_etiket else "HATA"
        self._sayac_etiket[key] = self._sayac_etiket.get(key, 0) + 1
        try:
            self.lbl_ozet.config(
                text=(
                    f"✓{self._sayac_etiket['UYGUN']}  "
                    f"✗{self._sayac_etiket['UYGUN_DEGIL']}  "
                    f"?{self._sayac_etiket['SUPHELI']}  "
                    f"KE{self._sayac_etiket['KONTROL_EDILEMEDI']}  "
                    f"⚡{self._sayac_etiket['HATA']}"
                )
            )
        except Exception:
            pass

    def yorum_ekle(self, no: int, ilac_adi: str,
                   sonuc_etiketi: str, ai_sonuc=None,
                   hata_mesaji: str = ""):
        """Bir reçetenin AI yorumunu panele append et.

        Args:
            no, ilac_adi: reçete sayaç + ilaç adı (başlık satırı)
            sonuc_etiketi: 'UYGUN' / 'UYGUN_DEGIL' / 'SUPHELI' / 'KONTROL_EDILEMEDI' / 'HATA'
            ai_sonuc: sonuc_parser.AISonuc instance (varsa) — şartlar + yorum çekilir
            hata_mesaji: AI çağrısı başarısızsa hata mesajı
        """
        if self._kapali:
            return
        try:
            self.txt_yorum.config(state="normal")

            # Başlık satırı (renkli banner)
            etiket_tr = {
                "UYGUN": "✓ UYGUN",
                "UYGUN_DEGIL": "✗ UYGUN DEĞİL",
                "SUPHELI": "? ŞÜPHELİ",
                "KONTROL_EDILEMEDI": "? KONTROL EDİLEMEDİ",
                "MANUEL_KONTROL_GEREKIR": "⚙ MANUEL",
                "HATA": "⚡ HATA",
            }.get(sonuc_etiketi, sonuc_etiketi)

            baslik = f"  {no}/{self.toplam} — {(ilac_adi or '')[:50]}   [{etiket_tr}]  \n"
            self.txt_yorum.insert("end", baslik, "h_recete")

            # Hata durumu
            if hata_mesaji or sonuc_etiketi == "HATA":
                self.txt_yorum.insert("end", "\n⚡ Hata: ", "h_alt")
                self.txt_yorum.insert("end", (hata_mesaji or "(detay yok)") + "\n\n")
            elif ai_sonuc is not None:
                # SUT referans
                if getattr(ai_sonuc, "sut_referans", ""):
                    self.txt_yorum.insert(
                        "end", f"\nSUT: {ai_sonuc.sut_referans}", "h_alt")
                    if getattr(ai_sonuc, "guven_skoru", 0):
                        self.txt_yorum.insert(
                            "end",
                            f"   ·   Güven: %{int(ai_sonuc.guven_skoru * 100)}\n")
                    else:
                        self.txt_yorum.insert("end", "\n")

                # ÖZET
                ozet = (getattr(ai_sonuc, "ozet_aciklama", "") or "").strip()
                if ozet:
                    self.txt_yorum.insert("end", "\n📝 Özet:\n", "h_alt")
                    self.txt_yorum.insert("end", ozet + "\n")

                # Sağlanan / Sağlanmayan / KE
                saglanan = getattr(ai_sonuc, "saglanan_sartlar", []) or []
                saglanmayan = getattr(ai_sonuc, "saglanmayan_sartlar", []) or []
                ke = getattr(ai_sonuc, "kontrol_edilemeyen_sartlar", []) or []

                if saglanan:
                    self.txt_yorum.insert(
                        "end", f"\n✓ Sağlanan ({len(saglanan)}):\n", "h_alt")
                    for s in saglanan:
                        self.txt_yorum.insert("end", f"   • {s}\n", "var")
                if saglanmayan:
                    self.txt_yorum.insert(
                        "end", f"\n✗ Sağlanmayan ({len(saglanmayan)}):\n", "h_alt")
                    for s in saglanmayan:
                        ad = s.get("sart", "") if isinstance(s, dict) else str(s)
                        nd = s.get("neden", "") if isinstance(s, dict) else ""
                        if nd:
                            self.txt_yorum.insert(
                                "end", f"   • {ad} — {nd}\n", "yok")
                        else:
                            self.txt_yorum.insert("end", f"   • {ad}\n", "yok")
                if ke:
                    self.txt_yorum.insert(
                        "end", f"\n? Kontrol edilemeyen ({len(ke)}):\n", "h_alt")
                    for s in ke:
                        ad = s.get("sart", "") if isinstance(s, dict) else str(s)
                        ek = s.get("eksik_veri", "") if isinstance(s, dict) else ""
                        if ek:
                            self.txt_yorum.insert(
                                "end", f"   • {ad} — {ek}\n", "ke")
                        else:
                            self.txt_yorum.insert("end", f"   • {ad}\n", "ke")

                # KLİNİK YORUM (ana içerik)
                klinik = (getattr(ai_sonuc, "klinik_yorum", "") or "").strip()
                if klinik:
                    self.txt_yorum.insert(
                        "end", "\n💬 Klinik Yorum:\n", "h_alt")
                    self.txt_yorum.insert("end", klinik + "\n", "klinik")

            self.txt_yorum.insert("end", "\n" + ("─" * 90) + "\n")
            self.txt_yorum.see("end")
        except Exception as e:
            logger.debug("yorum_ekle: %s", e)
        finally:
            try:
                self.txt_yorum.config(state="disabled")
            except Exception:
                pass

    def iptal_edildi_mi(self) -> bool:
        return self.iptal_istendi

    def _iptal_tikla(self):
        if self._kapali:
            return
        # Worker zaten tamamlandıysa direkt kapat
        if self._tamamlandi_flag:
            self.kapat()
            return
        # İlk tıkta graceful iptal iste, butonu "Şimdi Kapat (zorla)"ya çevir
        if not self.iptal_istendi:
            self.iptal_istendi = True
            try:
                self.btn_iptal.config(
                    text="✖ Pencereyi Şimdi Kapat (işlem arka planda devam eder)",
                    bg="#FFCDD2", fg="#B71C1C",
                    state="normal",
                    command=self._zorla_kapat,
                )
                self.lbl_ozet.config(
                    text="(iptal istendi — bitince kapanır, ya da Şimdi Kapat'a bas)",
                    fg="#EF6C00")
            except Exception:
                pass
            return
        # İkinci tıkta zorla kapat
        self._zorla_kapat()

    def _zorla_kapat(self):
        """Worker bitmemiş olsa bile pencereyi şimdi kapat (worker arka planda
        devam eder, kaydedilen sonuçlar DB'de korunur)."""
        self.iptal_istendi = True
        self.kapat()

    def tamamlandi(self):
        """Worker bitti — pencereyi otomatik kapatma, kullanıcı yorumları
        okuyup kendisi kapatsın. Sadece progressbar dur + İptal → Kapat."""
        if self._kapali:
            return
        self._tamamlandi_flag = True
        try:
            if self._timer_job:
                self.parent.after_cancel(self._timer_job)
                self._timer_job = None
        except Exception:
            pass
        try:
            self.pb.stop()
            self.pb.config(mode="determinate")
            try:
                self.pb["value"] = 100
            except Exception:
                pass
        except Exception:
            pass
        # Modal grab'i bırak — kullanıcı ana pencereye de erişebilsin
        try:
            self.win.grab_release()
        except Exception:
            pass
        # Pencerenin X butonu da artık temiz kapatsın
        try:
            self.win.protocol("WM_DELETE_WINDOW", self.kapat)
        except Exception:
            pass
        try:
            self.btn_iptal.config(
                text="✓ Tamamlandı — Kapat",
                bg="#E8F5E9", fg="#1B5E20", activebackground="#C8E6C9",
                state="normal",
                command=self.kapat,
            )
        except Exception:
            pass

    def kapat(self):
        if self._kapali:
            return
        self._kapali = True
        try:
            if self._timer_job:
                self.parent.after_cancel(self._timer_job)
        except Exception:
            pass
        try:
            self.pb.stop()
        except Exception:
            pass
        try:
            self.win.grab_release()
        except Exception:
            pass
        try:
            self.win.destroy()
        except Exception:
            pass


# ═══════════════════════════════════════════════════════════════════════
# 📸 EK GÖRSEL YÖNETİM DIALOG (per-satır)
# ═══════════════════════════════════════════════════════════════════════
class _EkGorselYonetDialog(tk.Toplevel):
    """Bir satıra eklenmiş ek görselleri yönet: ekle/sil/temizle.

    Görseller `gui_parent.ek_gorseller[ri_id]` içinde tutulur:
        {"klasor": Path, "yollar": [Path, ...]}

    Görsel ekleme:
      • 📷 Ekran Bölgesi Seç → BolgeSecimOverlay (screenshot_sorgu modülü)
      • 📂 Dosyadan Ekle    → filedialog ile PNG/JPG seç

    Diyalog kapanınca state korunur (AI Kontrol çağrısında kullanılacak).
    """

    def __init__(self, gui_parent, satir: dict, ri_id: str):
        super().__init__(gui_parent.root)
        self.gui = gui_parent
        self.satir = satir
        self.ri_id = str(ri_id)
        self.klasor = gui_parent._ek_gorsel_klasoru_olustur(self.ri_id)

        # State'i başlat (yoksa)
        if self.ri_id not in self.gui.ek_gorseller:
            self.gui.ek_gorseller[self.ri_id] = {
                "klasor": self.klasor,
                "yollar": [],
            }

        rec_no = satir.get("rec_no") or "—"
        ilac = (satir.get("ilac") or "—")[:40]
        self.title(f"📸 Ek Görsel Yönet — {rec_no} / {ilac}")
        self.geometry("680x520")
        self.minsize(560, 420)
        self.configure(bg="#FAFAFA")
        self.transient(gui_parent.root)
        try:
            self.grab_set()
        except Exception:
            pass

        # Üst banner
        ust = tk.Frame(self, bg="#0277BD", height=46)
        ust.pack(fill="x")
        ust.pack_propagate(False)
        tk.Label(
            ust, text="📸 AI Kontrol için Ek Görseller",
            font=("Segoe UI", 12, "bold"),
            bg="#0277BD", fg="white",
        ).pack(side="left", padx=14, pady=10)

        # Bilgi
        bilgi_metni = (
            f"  Reçete: {rec_no}    İlaç: {ilac}\n"
            "  Botanik DB'de eksik kalan bilgileri (önceki eczane ilaçları,\n"
            "  başka kurumdan raporlar) görselle tamamla. AI bunları\n"
            "  paket verisiyle KONSOLİDE edip değerlendirecek."
        )
        tk.Label(
            self, text=bilgi_metni, bg="#E1F5FE", fg="#01579B",
            justify="left", anchor="w", font=("Segoe UI", 9),
            padx=10, pady=6,
        ).pack(fill="x")

        # Görsel listesi
        liste_frame = tk.LabelFrame(
            self, text=" Eklenen Görseller ", bg="#FAFAFA",
            font=("Segoe UI", 9, "bold"), padx=8, pady=6,
        )
        liste_frame.pack(fill="both", expand=True, padx=10, pady=8)

        lst_ic = tk.Frame(liste_frame, bg="#FAFAFA")
        lst_ic.pack(fill="both", expand=True)
        vsb = ttk.Scrollbar(lst_ic, orient="vertical")
        vsb.pack(side="right", fill="y")
        self.lst = tk.Listbox(
            lst_ic, font=("Consolas", 9), bg="#FFFFFF",
            yscrollcommand=vsb.set, selectmode="extended",
        )
        self.lst.pack(side="left", fill="both", expand=True)
        vsb.config(command=self.lst.yview)

        # Butonlar
        btn_frame = tk.Frame(self, bg="#FAFAFA")
        btn_frame.pack(fill="x", padx=10, pady=(2, 4))
        tk.Button(
            btn_frame, text="📷 Ekran Bölgesi Seç",
            font=("Segoe UI", 10, "bold"),
            bg="#0277BD", fg="white", activebackground="#01579B",
            relief="flat", bd=0, padx=12, cursor="hand2",
            command=self._bolge_sec,
        ).pack(side="left", padx=2)
        tk.Button(
            btn_frame, text="📂 Dosyadan Ekle",
            font=("Segoe UI", 10),
            bg="#E1F5FE", fg="#01579B",
            relief="flat", bd=1, padx=12, cursor="hand2",
            command=self._dosyadan_ekle,
        ).pack(side="left", padx=2)
        tk.Button(
            btn_frame, text="🗑 Seçili Sil",
            font=("Segoe UI", 10),
            bg="#FFEBEE", fg="#B71C1C",
            relief="flat", bd=1, cursor="hand2",
            command=self._secili_sil,
        ).pack(side="right", padx=2)
        tk.Button(
            btn_frame, text="🧹 Tümünü Temizle",
            font=("Segoe UI", 10),
            bg="#FAFAFA", fg="#999",
            relief="flat", bd=1, cursor="hand2",
            command=self._tumunu_sil,
        ).pack(side="right", padx=2)

        alt = tk.Frame(self, bg="#FAFAFA")
        alt.pack(fill="x", padx=10, pady=(4, 10))
        self.lbl_durum = tk.Label(
            alt, text="", font=("Segoe UI", 9), bg="#FAFAFA", fg="#555",
            anchor="w",
        )
        self.lbl_durum.pack(side="left", fill="x", expand=True)
        tk.Button(
            alt, text="✓ Kapat (görseller saklanır)",
            font=("Segoe UI", 10),
            bg="#E8F5E9", fg="#1B5E20",
            relief="flat", cursor="hand2",
            command=self.destroy,
        ).pack(side="right", padx=2)

        self._listeyi_yenile()

    def _listeyi_yenile(self):
        self.lst.delete(0, "end")
        st = self.gui.ek_gorseller.get(self.ri_id, {"yollar": []})
        yollar = st.get("yollar", [])
        for i, yol in enumerate(yollar, 1):
            from pathlib import Path
            ad = Path(str(yol)).name
            try:
                boyut = Path(str(yol)).stat().st_size // 1024
                self.lst.insert("end", f"  {i:2d}.  {ad}   ({boyut} KB)")
            except Exception:
                self.lst.insert("end", f"  {i:2d}.  {ad}")
        n = len(yollar)
        self.lbl_durum.config(
            text=f"{n} görsel ekli — AI Kontrol bu reçeteye geldiğinde "
            f"görsel + DB verisi birlikte gönderilecek."
            if n else "Henüz görsel eklenmedi."
        )

    def _bolge_sec(self):
        """Ekran bölgesi seçimi → screenshot kaydet → listeye ekle."""
        try:
            from recete_kontrol.ai_kontrol.screenshot_sorgu import (
                BolgeSecimOverlay,
            )
        except ImportError as e:
            messagebox.showerror(
                "Modül Hatası",
                f"Screenshot modülü yüklenemedi:\n{e}\n\n"
                "Gereksinim: pip install Pillow",
                parent=self)
            return

        # Dialog'u geçici gizle (overlay tam ekran kaplayacak)
        self.withdraw()
        try:
            overlay = BolgeSecimOverlay(self.gui.root)
            overlay.wait_window()
            bbox = getattr(overlay, "bbox", None)
            ekran_resmi = getattr(overlay, "ekran_resmi", None)
        except Exception as e:
            self.deiconify()
            messagebox.showerror(
                "Ekran Seçimi", f"Hata: {type(e).__name__}: {e}",
                parent=self)
            return

        self.deiconify()

        if not bbox or not ekran_resmi:
            return  # iptal

        try:
            from datetime import datetime
            from pathlib import Path
            x1, y1, x2, y2 = bbox
            kirpilmis = ekran_resmi.crop((x1, y1, x2, y2))
            zaman = datetime.now().strftime("%H%M%S")
            seq = len(self.gui.ek_gorseller[self.ri_id]["yollar"]) + 1
            dosya = self.klasor / f"ss_{seq:02d}_{zaman}.png"
            kirpilmis.save(str(dosya), "PNG")
            self.gui.ek_gorseller[self.ri_id]["yollar"].append(dosya)
            self._listeyi_yenile()
        except Exception as e:
            messagebox.showerror(
                "Kaydetme Hatası",
                f"Görsel kaydedilemedi: {type(e).__name__}: {e}",
                parent=self)

    def _dosyadan_ekle(self):
        """Disk üzerinden PNG/JPG seçimi."""
        from pathlib import Path
        yollar = filedialog.askopenfilenames(
            title="Görsel(ler) seç — PNG/JPG",
            parent=self,
            filetypes=[
                ("Resimler", "*.png *.jpg *.jpeg"),
                ("PNG", "*.png"),
                ("JPEG", "*.jpg *.jpeg"),
                ("Tümü", "*.*"),
            ],
        )
        if not yollar:
            return
        # Klasöre kopyala (Read aracı tek klasör altındaki dosyalara erişiyor)
        import shutil
        from datetime import datetime
        eklendi = 0
        for src in yollar:
            try:
                src_p = Path(src)
                zaman = datetime.now().strftime("%H%M%S")
                seq = len(self.gui.ek_gorseller[self.ri_id]["yollar"]) + 1
                hedef = self.klasor / f"dosya_{seq:02d}_{zaman}{src_p.suffix.lower()}"
                shutil.copy2(src_p, hedef)
                self.gui.ek_gorseller[self.ri_id]["yollar"].append(hedef)
                eklendi += 1
            except Exception as e:
                logger.warning("Dosya kopyalanamadı %s: %s", src, e)
        if eklendi:
            self._listeyi_yenile()

    def _secili_sil(self):
        secili = self.lst.curselection()
        if not secili:
            return
        yollar = self.gui.ek_gorseller[self.ri_id]["yollar"]
        # Tersten sil (index kaymasın)
        for idx in sorted(secili, reverse=True):
            if 0 <= idx < len(yollar):
                yol = yollar.pop(idx)
                try:
                    from pathlib import Path
                    Path(str(yol)).unlink(missing_ok=True)
                except Exception:
                    pass
        self._listeyi_yenile()

    def _tumunu_sil(self):
        if not self.gui.ek_gorseller[self.ri_id]["yollar"]:
            return
        if not messagebox.askyesno(
            "Tümünü Sil",
            f"{len(self.gui.ek_gorseller[self.ri_id]['yollar'])} görsel "
            "silinecek. Emin misiniz?",
            parent=self,
        ):
            return
        self.gui._ek_gorsel_temizle(self.ri_id)
        # Klasörü yeniden oluştur (yeni eklemeler için)
        self.klasor = self.gui._ek_gorsel_klasoru_olustur(self.ri_id)
        self.gui.ek_gorseller[self.ri_id] = {
            "klasor": self.klasor, "yollar": [],
        }
        self._listeyi_yenile()


# ═══════════════════════════════════════════════════════════════════════
# ANA SINIF
# ═══════════════════════════════════════════════════════════════════════
class AylikReceteSorguGUI:
    """Aylık reçete-ilaç inceleme & filtreleme tablosu."""

    STATE_DOSYASI = "aylik_inceleme_state.json"
    SUTUN_AYAR_DOSYASI = "aylik_inceleme_sutun_ayarlari.json"
    SUTUN_SABLON_DOSYASI = "aylik_inceleme_sutun_sablonlari.json"

    def __init__(self, root: tk.Tk, ana_menu_callback=None):
        self.root = root
        self.ana_menu_callback = ana_menu_callback

        self.root.title("📋  AYLIK İNCELEME & FİLTRELEME  ·  BOTANİK EOS  ·  SALT OKUNUR")
        # Geçici varsayılan boyut (zoomed çalışmazsa fallback)
        self.root.geometry("1700x920")
        # Pencere açılır açılmaz tam ekrana (maximized) gelsin
        try:
            # Windows ve çoğu modern Tk için
            self.root.state("zoomed")
        except tk.TclError:
            try:
                # Linux varyantı
                self.root.attributes("-zoomed", True)
            except Exception:
                # Son fallback: ekran boyutuna oturt
                try:
                    sw = self.root.winfo_screenwidth()
                    sh = self.root.winfo_screenheight()
                    self.root.geometry(f"{sw}x{sh}+0+0")
                except Exception:
                    pass
        try:
            from eczasist_ikon import ikon_uygula
            ikon_uygula(self.root)
        except Exception:
            pass

        self.db: BotanikDB = None

        # Lookup cache
        self._lookup_kapsam = {}
        self._lookup_brans = {}
        self._lookup_etkin_madde = {}
        self._lookup_alttur = {}
        self._lookup_renk = {}
        self._lookup_provizyon = {}
        self._lookup_rapor_kodu = {}
        self._lookup_kurum = {}
        self._lookup_hastane_kodu = {}  # HastaneId → HastaneKodu (tesis kodu)

        # Veri
        self.tum_satirlar = []        # tüm sorgu sonucu (filtresiz)
        self.gosterilen_iids = set()  # şu anda görünen iid'ler
        self.satir_indeks = {}        # {iid: satir_dict}
        self.satir_renkleri = {}      # {iid: renk}
        self.secili_iidler = set()    # checkbox ile seçilmiş satırlar

        # AI Kontrol için satıra eklenmiş ek görseller
        # {ri_id: {"klasor": Path, "yollar": [Path, ...]}}
        # Eczacı Botanik DB'de eksik kalan bilgileri (önceki eczane ilaçları,
        # başka kurumdan raporlar) ekran görüntüsü ile tamamlar; AI worker
        # bu görsel varsa multimodal path'e düşer.
        self.ek_gorseller: Dict[str, Dict[str, Any]] = {}

        # Filtre durumu
        self.aktif_sutun_filtre = {}  # {sutun_kod: arama_metni}
        self.aktif_deger_filtre = {}  # {sutun_kod: set(secili_degerler)}  Excel-benzeri
        # Çoklu koşul: {sutun_kod: [{"baglac": None|"ve"|"veya",
        #                            "op": "icerir"|..., "deger": "..."}, ...]}
        # İlk koşulun baglac'ı None. VEYA grup ayırıcı, VE grup içi.
        # Eşleşme = HERHANGİ bir grubun TÜM koşulları sağlanır.
        # (Geriye dönük: eski (op, deger) tuple tek-koşul listeye normalize edilir.)
        self.aktif_metin_filtre = {}
        self.aktif_renk_filtre = {RENK_BEYAZ, RENK_YESIL, RENK_SARI,
                                    RENK_TURUNCU, RENK_KIRMIZI, RENK_GRI}
        # "Boş satırları gizle" — uyarı kodu / mesaj / rapor kodu olmayan
        # satırları liste dışı tutar (kontrol gerektirmeyen temiz satırlar).
        # Varsayılan AÇIK: kullanıcı kontrol gerektirebilecek satırlara
        # odaklansın diye temiz satırlar baştan elenir.
        self.gizle_bos_satirlar = tk.BooleanVar(value=True)

        # Verdict (kontrol sonucu) filtre — kullanıcı tabloyu sonuç etiketine
        # göre filtreleyebilsin: UYGUN / UYGUN DEĞİL / ŞÜPHELİ / ŞARTLI UYGUN /
        # MANUEL KONTROL / boş (henüz kontrol edilmemiş). Default hepsi açık.
        # _satir_filtreden_geciyor_mu erken kontrol yapar; etiket görünmez ise
        # satır dışlanır. UI: row3 üstünde panel olarak.
        self.var_verdict_filtre = {
            "UYGUN":              tk.BooleanVar(value=True),
            "UYGUN DEĞİL":        tk.BooleanVar(value=True),
            "ŞÜPHELİ":            tk.BooleanVar(value=True),
            "ŞARTLI UYGUN":       tk.BooleanVar(value=True),
            "MANUEL KONTROL":     tk.BooleanVar(value=True),
            "DİĞER RAPOR UYGUN":  tk.BooleanVar(value=True),
            "":                   tk.BooleanVar(value=True),  # henüz kontrol edilmemiş
        }
        # Manuel teyit filtresi — recete_teyit_db sabitleri (UYGUN/SUPHELI/UYGUN_DEGIL/
        # DIGER_RAPOR_UYGUN). "":True → teyit edilmemiş satırlar görünür.
        self.var_teyit_filtre = {
            "UYGUN":              tk.BooleanVar(value=True),
            "SUPHELI":            tk.BooleanVar(value=True),
            "UYGUN_DEGIL":        tk.BooleanVar(value=True),
            "DIGER_RAPOR_UYGUN":  tk.BooleanVar(value=True),
            "":                   tk.BooleanVar(value=True),  # teyit edilmemiş
        }

        # Detaylı filtre ayarları (⚙ butonundan açılan pencere ile yönetilir)
        try:
            import aylik_filtre_ayarlari as fa
            self._filtre_ayarlari_aktif = fa.ayarlari_yukle()
        except Exception:
            self._filtre_ayarlari_aktif = None

        # Aktif dönem (yıl-ay) — state için anahtar
        self.aktif_donem = ""

        # Sütun görünüm ayarı — varsayılan tüm sütunlar açık
        self.sutun_gosterim = {kod: True for kod in SUTUN_KOD}
        self._sutun_ayarlarini_yukle()

        # Sıralama durumu (Excel benzeri tıkla-sırala)
        self._siralama_kolonu = None
        self._siralama_yonu = None  # "asc" | "desc"

        # Arayüz
        self._arayuz_olustur()

        # Son aktif sütun şablonunu uygula (varsa) — tablo kuruldu, widths hazır
        try:
            self._aktif_sablonu_uygula()
        except Exception as e:
            logger.debug("Açılışta şablon uygulama: %s", e)

        # Async başlat
        self.root.after(100, self._db_baglan_async)

    # ------------------------------------------------------------------ DB
    def _db_baglan_async(self):
        threading.Thread(target=self._db_baglan_ve_lookup, daemon=True).start()

    def _db_baglan_ve_lookup(self):
        try:
            self.db = BotanikDB(production=True)
            if not self.db.baglan():
                raise RuntimeError("Botanik veritabanına bağlanılamadı")
            self.root.after(0, self._durum_yaz, "DB bağlandı (salt-okunur). Lookup yükleniyor…")
            self._lookup_yukle()
            self.root.after(0, self._lookup_bitti)
        except Exception as e:
            logger.error("DB bağlantı hatası: %s", e)
            self.root.after(0, self._durum_yaz, f"DB hatası: {e}")
            self.root.after(0, lambda: messagebox.showerror(
                "Bağlantı Hatası",
                f"Botanik EOS veritabanına bağlanılamadı:\n{e}"), parent=self.root)

    def _lookup_yukle(self):
        if not self.db:
            return
        try:
            for r in self.db.sorgu_calistir("SELECT KapsamId, KapsamAdi FROM Kapsam"):
                self._lookup_kapsam[r["KapsamId"]] = r["KapsamAdi"]
            for r in self.db.sorgu_calistir(
                "SELECT BransId, BransAdi FROM Brans WHERE BransSilme=0"):
                self._lookup_brans[r["BransId"]] = r["BransAdi"]
            for r in self.db.sorgu_calistir(
                "SELECT EtkinMaddeId, EtkinMaddeSGKKodu, EtkinMaddeAdi "
                "FROM EtkinMadde WHERE EtkinMaddeSilme=0"):
                self._lookup_etkin_madde[r["EtkinMaddeId"]] = (
                    r["EtkinMaddeSGKKodu"] or "", r["EtkinMaddeAdi"] or "")
            for r in self.db.sorgu_calistir(
                "SELECT ReceteAltTuruId, ReceteAltTuruAdi FROM ReceteAltTuru "
                "WHERE ReceteAltTuruSilme=0"):
                self._lookup_alttur[r["ReceteAltTuruId"]] = r["ReceteAltTuruAdi"]
            for r in self.db.sorgu_calistir(
                "SELECT ReceteRenkId, ReceteRenkAdi FROM ReceteRenk "
                "WHERE ReceteRenkSilme=0"):
                self._lookup_renk[r["ReceteRenkId"]] = r["ReceteRenkAdi"]
            # Kırmızı/Yeşil/Mor reçete tipi ID setleri (renkli reçete kontrolü
            # için her zaman gelmeli — boş satır filtresinden muaf)
            self._renkli_recete_idler = {
                rid: ad for rid, ad in self._lookup_renk.items()
                if ad and ad.strip().lower() in ("kırmızı", "kirmizi",
                                                    "yeşil", "yesil", "mor")
            }
            for r in self.db.sorgu_calistir(
                "SELECT ProvizyonTipId, ProvizyonTipAdi FROM ProvizyonTipi "
                "WHERE ProvizyonTipSilme=0"):
                self._lookup_provizyon[r["ProvizyonTipId"]] = r["ProvizyonTipAdi"]
            for r in self.db.sorgu_calistir(
                "SELECT RaporKodId, RaporKodu, RaporKodAciklama FROM RaporKodlari "
                "WHERE RaporKodSilme=0"):
                self._lookup_rapor_kodu[r["RaporKodId"]] = (
                    r["RaporKodu"] or "", r["RaporKodAciklama"] or "")
            for r in self.db.sorgu_calistir(
                "SELECT KurumId, KurumAdi FROM Kurum WHERE KurumSilme=0"):
                self._lookup_kurum[r["KurumId"]] = r["KurumAdi"]
            for r in self.db.sorgu_calistir(
                "SELECT HastaneId, HastaneKodu FROM Hastane "
                "WHERE HastaneSilme=0 AND HastaneKodu IS NOT NULL"):
                self._lookup_hastane_kodu[r["HastaneId"]] = (
                    r["HastaneKodu"] or "")
        except Exception as e:
            logger.exception("Lookup hatası: %s", e)

    def _lookup_bitti(self):
        self._durum_yaz(
            f"Hazır — {len(self._lookup_etkin_madde)} etkin madde, "
            f"{len(self._lookup_brans)} branş, "
            f"{len(self._lookup_rapor_kodu)} rapor kodu yüklendi"
        )
        self._ay_listesini_yukle()

    # --------------------------------------------------------------- LAYOUT
    def _arayuz_olustur(self):
        # ═══════════════════════════════════════════════════════════════════
        # 2 KATMAN — ÜST: Veri/Sayım/Araçlar | ALT: Renkli kontrol panelleri
        # ═══════════════════════════════════════════════════════════════════

        HEADER_BG = "#37474F"
        HEADER_FG = "#FFFFFF"
        HEADER_LBL_FG = "#B0BEC5"
        FONT_PRIMARY = ("Segoe UI", 11, "bold")
        FONT_GROUP = ("Segoe UI", 9, "bold")
        FONT_BUTON = ("Segoe UI", 9, "bold")
        FONT_LABEL_SM = ("Segoe UI", 8, "bold")

        renk_kisa = {
            RENK_YESIL:   "🟢", RENK_SARI:    "🟡",
            RENK_TURUNCU: "🟠", RENK_KIRMIZI: "🔴",
            RENK_BEYAZ:   "⚪", RENK_GRI:     "🩶",
        }
        renk_aciklama = {
            RENK_YESIL:   "YEŞİL — Uygun (elendi)",
            RENK_SARI:    "SARI — Manuel kontrol gerekli",
            RENK_TURUNCU: "TURUNCU — Şüpheli",
            RENK_KIRMIZI: "KIRMIZI — Uygunsuz",
            RENK_BEYAZ:   "BEYAZ — Renksiz / sıfırla",
            RENK_GRI:     "GRİ — Kontrol gerekmez "
                            "(ilaç dışlama listesine eklenir)",
        }
        renk_etiket = {
            RENK_BEYAZ:   "⚪ Beyaz",
            RENK_YESIL:   "🟢 Yeşil",
            RENK_SARI:    "🟡 Sarı",
            RENK_TURUNCU: "🟠 Turuncu",
            RENK_KIRMIZI: "🔴 Kırmızı",
            RENK_GRI:     "🩶 Gri",
        }

        # ════════════════════════════════════════════════════════════════
        # ÜST SATIR — DATA + STATUS + TOOLS (koyu zemin)
        # ════════════════════════════════════════════════════════════════
        row1 = tk.Frame(self.root, bg=HEADER_BG, height=44)
        row1.pack(fill="x")
        row1.pack_propagate(False)

        # ── SOL: DÖNEM grubu (Yıl + Ay + SORGULA) ──
        sol = tk.Frame(row1, bg=HEADER_BG)
        sol.pack(side="left", padx=10, pady=5)

        tk.Label(sol, text="📅 DÖNEM", bg=HEADER_BG, fg=HEADER_LBL_FG,
                 font=FONT_LABEL_SM).pack(side="left", padx=(0, 8))

        tk.Label(sol, text="Yıl", bg=HEADER_BG, fg=HEADER_FG,
                 font=("Segoe UI", 9)).pack(side="left", padx=(0, 3))
        # Yıl çoklu seçim — DB'den yüklenince set_ogeler ile doldurulur
        self.var_yil = tk.StringVar()  # geri uyum (compat shim)
        self.cb_yil = MultiSelectDropdown(
            sol, ["Tümü"], varsayilan="Tümü", baslik="Yıl",
            on_change=self._yil_degisti, width=10,
        )
        self.cb_yil.pack(side="left", padx=2)
        _Tooltip(self.cb_yil,
                  "Yıl seçimi (çoklu).\n'Tümü' = tüm yıllar (büyük veri seti)")

        tk.Label(sol, text="Ay", bg=HEADER_BG, fg=HEADER_FG,
                 font=("Segoe UI", 9)).pack(side="left", padx=(8, 3))
        # Ay çoklu seçim — sabit 12 ay
        self.var_ay = tk.StringVar()  # geri uyum (compat shim)
        _ay_ogeleri = ["Tümü"] + [self._ay_etiketi(i) for i in range(1, 13)]
        self.cb_ay = MultiSelectDropdown(
            sol, _ay_ogeleri, varsayilan="Tümü", baslik="Ay",
            width=16,
        )
        self.cb_ay.pack(side="left", padx=2)
        _Tooltip(self.cb_ay,
                  "Ay seçimi (çoklu).\n'Tümü' = seçili yıldaki tüm aylar")

        btn = tk.Button(sol, text="🔍 SORGULA", bg="#1976D2", fg="white",
                         activebackground="#1565C0", bd=0,
                         command=self._receteleri_sorgula,
                         padx=14, pady=4, font=FONT_PRIMARY)
        btn.pack(side="left", padx=(10, 0))
        _Tooltip(btn,
                  "Seçili yıl/ay için Botanik EOS'tan reçete-ilaç satırlarını "
                  "yükle (sadece okuma).")

        # ── SAĞ: ARAÇLAR (Excel + Sütunlar) ──
        sag = tk.Frame(row1, bg=HEADER_BG)
        sag.pack(side="right", padx=10, pady=5)

        btn = tk.Button(sag, text="📊 Excel", bg="#43A047", fg="white",
                         activebackground="#388E3C", bd=0,
                         command=self._excel_export, padx=12, pady=3,
                         font=FONT_BUTON)
        btn.pack(side="right", padx=2)
        _Tooltip(btn, "Tabloyu (renk + sütunlarla) Excel dosyasına aktar")

        btn = tk.Button(sag, text="⚙ Sütunlar", bg="#546E7A", fg="white",
                         activebackground="#455A64", bd=0,
                         command=self._sutun_ayar_penceresi, padx=12, pady=3,
                         font=FONT_BUTON)
        btn.pack(side="right", padx=2)
        _Tooltip(btn, "Görünür sütunları ayarla (göster/gizle)")

        # ── ORTA: SAYIM (lbl_sayim) ──
        self.lbl_sayim = tk.Label(row1, text="", bg=HEADER_BG, fg=HEADER_FG,
                                    font=("Segoe UI", 10, "bold"))
        self.lbl_sayim.pack(side="left", padx=20, expand=True)
        _Tooltip(self.lbl_sayim,
                  "Toplam yüklenen / filtrelenmiş satır sayısı")

        # ════════════════════════════════════════════════════════════════
        # ALT SATIR(LAR) — KONTROL PANELLERİ + HÜCRE GÖSTERGESİ
        # Sol kolon (2 sıra):  Sıra A → Seçim + Boyama
        #                      Sıra B → Göster + Filtreleri Sıfırla
        # Sağ kolon (2 sıra yüksekliğinde): Hücre içeriği göstergesi
        # ════════════════════════════════════════════════════════════════
        ust_alan = tk.Frame(self.root, bg="#FAFAFA")
        ust_alan.pack(fill="x", padx=4, pady=(2, 2))

        sol_kol = tk.Frame(ust_alan, bg="#FAFAFA")
        sol_kol.pack(side="left", fill="y")

        row2 = tk.Frame(sol_kol, bg="#FAFAFA")
        row2.pack(fill="x", pady=(0, 2))

        # Verdict (kontrol sonucu) filtresi — row3'ün ÜSTÜNDE
        # (kontrol butonlarının üstündeki küçük boş alan).
        # Renkli checkbox'lar — etiketlere göre tabloyu filtreler.
        row_verdict = tk.Frame(sol_kol, bg="#FAFAFA")
        row_verdict.pack(fill="x", pady=(0, 2))

        # Manuel teyit filtre satırı — verdict satırının ALTINDA, aynı tarzda.
        # 🩺 GEÇMİŞ TARA da bu satırın sağına yerleştirilir (kullanıcı isteği
        # 2026-05-20: teyit butonlarının sağındaki boşluğa).
        row_teyit = tk.Frame(sol_kol, bg="#FAFAFA")
        row_teyit.pack(fill="x", pady=(0, 2))

        row3 = tk.Frame(sol_kol, bg="#FAFAFA")
        row3.pack(fill="x", pady=(0, 0))

        sag_kol = tk.Frame(ust_alan, bg="#FAFAFA")
        sag_kol.pack(side="left", fill="both", expand=True, padx=(2, 0))

        def _panel_olustur(parent, baslik, baslik_fg, panel_bg):
            """Renkli arka planlı, başlık etiketli kompakt panel."""
            p = tk.Frame(parent, bg=panel_bg, bd=1, relief="solid")
            p.pack(side="left", padx=2, pady=1, fill="y")
            tk.Label(p, text=baslik, bg=panel_bg, fg=baslik_fg,
                     font=FONT_GROUP).pack(side="left", padx=(6, 6),
                                              pady=4)
            return p

        # ─── PANEL 1: SEÇİM (açık mavi) ───
        P_SECIM_BG = "#E3F2FD"
        p1 = _panel_olustur(row2, "🎯 Seçim", "#0D47A1", P_SECIM_BG)
        for txt, cmd, tip in [
            ("☑ Tümü", self._tumunu_sec,
             "Filtreden geçen tüm satırları SEÇ"),
            ("☐ Hiçbiri", self._hicbirini_secme,
             "Filtreden geçen satırların seçimini KALDIR"),
            ("↻ Tersine", self._secimi_tersine_cevir,
             "Seçimi tersine çevir (filtreli satırlarda)"),
            ("✓ Vurgulu", self._vurgulanmislari_isaretle,
             "Shift/Ctrl ile vurgulanmış satırların\n"
             "checkbox'larını işaretle"),
        ]:
            b = tk.Button(p1, text=txt, bg="white", bd=1,
                          command=cmd, padx=8, pady=3, font=FONT_BUTON)
            b.pack(side="left", padx=2, pady=4)
            _Tooltip(b, tip)
        tk.Frame(p1, bg=P_SECIM_BG, width=4).pack(side="left")

        # ─── PANEL 2: BOYAMA (açık sarı) — TEK PARÇA + radio mod selector ───
        P_BOYA_BG = "#FFF8E1"
        p2 = _panel_olustur(row2, "🎨 Boyama", "#E65100", P_BOYA_BG)

        # Mod seçici: Seçili / Filtreli (radiobutton — yer kazanır)
