    def _tablo_kur(self, parent):
        """Tablo + sütun-hizalı filtre satırı (tek yatay scroll ile birlikte)."""
        cont = tk.Frame(parent, bg="white")
        cont.pack(fill="both", expand=True, padx=4, pady=4)

        # Style: kompakt satırlar
        style = ttk.Style()
        try:
            style.configure("Inceleme.Treeview", rowheight=22, font=("Segoe UI", 9))
            style.configure("Inceleme.Treeview.Heading",
                            font=("Segoe UI", 9, "bold"))
        except Exception:
            pass

        # Yatay ölçüler — filtre ve tablo görünür alanı eşitlemek için
        FILTRE_H = 28           # filtre satırı yüksekliği (px)
        SAG_PAD = 18            # ttk Scrollbar genişliği (yaklaşık ysb)

        # ─────────── Yatay scrollbar (en altta) ───────────
        # Önce alta sabitliyoruz ki filtre + tablo onun üstünde dizilsin.
        xsb = ttk.Scrollbar(cont, orient="horizontal")
        xsb.pack(fill="x", side="bottom", padx=(0, SAG_PAD))

        # ─────────── Filtre satırı (sütunların ÜSTÜNDE — Excel benzeri) ───────────
        # Tablonun ysb genişliği kadar sağdan boşluk bırakıyoruz ki filtre
        # alanı tablo görünür alanıyla pixel-pixel aynı olsun.
        filtre_satir = tk.Frame(cont, bg="#ECEFF1", height=FILTRE_H)
        filtre_satir.pack(fill="x", side="top", pady=(0, 2))
        filtre_satir.pack_propagate(False)

        tk.Frame(filtre_satir, width=SAG_PAD, bg="#ECEFF1"
                 ).pack(side="right", fill="y")

        self._filtre_canvas = tk.Canvas(filtre_satir, bg="#ECEFF1",
                                         highlightthickness=0,
                                         height=FILTRE_H)
        self._filtre_canvas.pack(side="left", fill="both", expand=True)

        filtre_inner = tk.Frame(self._filtre_canvas, bg="#ECEFF1")
        self._filtre_canvas.create_window((0, 0), window=filtre_inner,
                                            anchor="nw")

        self.arama_varlari = {}
        # Placeholder durum izleyici — True iken filtreye etki etmez
        self._placeholder_aktif = {}
        self._placeholder_metni = {}
        toplam_gen = 0
        PH_FG = "#9E9E9E"      # silik gri
        AKTIF_FG = "#000000"   # kullanıcı yazısı
        for kod, baslik, gen, _tip in SUTUNLAR:
            slot = tk.Frame(filtre_inner, bg="#ECEFF1",
                            width=gen, height=FILTRE_H)
            slot.pack(side="left")
            slot.pack_propagate(False)
            v = tk.StringVar()
            ent = tk.Entry(slot, textvariable=v,
                            font=("Segoe UI", 8, "italic"),
                            relief="solid", bd=1, fg=PH_FG)
            ent.place(x=1, y=4, width=gen - 2, height=20)

            # Placeholder mantığı — başlık silik gri/italik olarak içeride
            self._placeholder_metni[kod] = baslik

            def _ph_goster(k=kod, e=ent, vv=v, ph=baslik):
                if not vv.get():
                    self._placeholder_aktif[k] = True
                    vv.set(ph)
                    e.config(fg=PH_FG, font=("Segoe UI", 8, "italic"))

            def _ph_gizle(k=kod, e=ent, vv=v):
                if self._placeholder_aktif.get(k):
                    self._placeholder_aktif[k] = False
                    vv.set("")
                    e.config(fg=AKTIF_FG, font=("Segoe UI", 8))

            ent.bind("<FocusIn>", lambda _e, fn=_ph_gizle: fn())
            ent.bind("<FocusOut>", lambda _e, fn=_ph_goster: fn())

            v.trace_add("write",
                         lambda *a, k=kod: self._sutun_filtre_degisti(k))
            self.arama_varlari[kod] = v
            # Başlangıçta placeholder göster
            _ph_goster()
            toplam_gen += gen

        filtre_inner.update_idletasks()
        self._filtre_canvas.config(scrollregion=(0, 0, toplam_gen, FILTRE_H))

        # ─── Body: tablo (üst) + devre şeması paneli (alt) ───────────────
        body_frame = tk.Frame(cont, bg="white")
        body_frame.pack(fill="both", expand=True, side="top")

        # Devre şeması paneli ALTTA, yatay akış için tam genişlik + sabit yükseklik
        # Açılır/kapanır: tablonun 1/3'ü (380px) ↔ 1/2'si (genişletilmiş)
        self._sema_yukseklikler = {"normal": 600, "buyuk": 820, "kucuk": 50}
        self._sema_durum = "normal"
        self.sema_frame = tk.Frame(body_frame, bg="#FAFBFC",
                                    height=self._sema_yukseklikler["normal"],
                                    relief="solid", bd=2)
        self.sema_frame.pack(side="bottom", fill="x", pady=(4, 0))
        self.sema_frame.pack_propagate(False)
        try:
            self._sema_kur(self.sema_frame)
            import logging
            logging.getLogger(__name__).info(
                "SEMA: sema_frame oluştu, _sema_kur tamamlandı (h=%d)",
                self._sema_yukseklikler["normal"])
            # Geometry'i ölç (pack uygulandıktan sonra)
            def _olc():
                try:
                    bf = body_frame
                    sf = self.sema_frame
                    logging.getLogger(__name__).info(
                        "SEMA GEO: body=%dx%d (y=%d), sema=%dx%d (y=%d) "
                        "ismapped=%s",
                        bf.winfo_width(), bf.winfo_height(), bf.winfo_y(),
                        sf.winfo_width(), sf.winfo_height(), sf.winfo_y(),
                        sf.winfo_ismapped())
                except Exception as e2:
                    logging.getLogger(__name__).error("SEMA GEO HATA: %s", e2)
            self.root.after(800, _olc)
        except Exception as e:
            import logging, traceback
            logging.getLogger(__name__).error(
                "SEMA HATASI: _sema_kur fail: %s\n%s", e, traceback.format_exc())

        tree_frame = tk.Frame(body_frame, bg="white")
        tree_frame.pack(fill="both", expand=True, side="top")

        kolonlar = tuple(SUTUN_KOD)
        self.tv = ttk.Treeview(tree_frame, columns=kolonlar, show="headings",
                                selectmode="extended", style="Inceleme.Treeview")
        for kod, baslik, gen, _tip in SUTUNLAR:
            self.tv.heading(kod, text=baslik,
                            command=lambda k=kod: self._sutuna_gore_sirala(k))
            self.tv.column(kod, width=gen, minwidth=30, stretch=False)

        ysb = ttk.Scrollbar(tree_frame, orient="vertical",
                             command=self.tv.yview)
        ysb.pack(side="right", fill="y")
        self.tv.pack(side="left", fill="both", expand=True)
        self.tv.configure(yscrollcommand=ysb.set)

        # Renk tag'leri
        for renk, bg in RENK_BG.items():
            fg = RENK_FG[renk]
            self.tv.tag_configure(renk, background=bg, foreground=fg)

        # Teyit edilmiş satır için kalın font (rozetli satır vurgusu)
        self.tv.tag_configure("teyit_bold", font=("Segoe UI", 9, "bold"))

        # Kod+tarih fallback eşleşmesi — Rapor Kod ve Rap.Teşhis/Tak.No
        # değerleri kırmızı yazılsın (ttk.Treeview hücre-bazlı renk
        # desteklemediği için satır foreground'u kırmızıya çekilir; hücre
        # değerine ayrıca ⚠ işareti eklenir).
        self.tv.tag_configure("fallback_kirmizi", foreground="#C62828")

        # Olay bind'leri
        self.tv.bind("<Button-3>", self._sag_tik_dispatch)
        self.tv.bind("<Double-1>", self._satir_detay)
        self.tv.bind("<Button-1>", self._sol_tik_dispatch, add="+")
        # Tek tıklamada şema panelini güncelle
        self.tv.bind("<<TreeviewSelect>>", self._sema_secim_guncelle, add="+")
        # SS buton sayacını (aktif satırın ek görsel sayısı) güncelle
        self.tv.bind("<<TreeviewSelect>>",
                     self._ss_buton_sayac_guncelle, add="+")
        # Sütun genişlikleri değiştiğinde filtre slotlarını yeniden hizala.
        # Treeview'in column-resize özel event'i yok; mouse release sonrası
        # küçük bir gecikme ile güncel genişlikleri okuruz.
        def _siralama_sonrasi_hizala(_e=None):
            self.root.after(60, self._filtre_slotlarini_hizala)
        self.tv.bind("<ButtonRelease-1>", _siralama_sonrasi_hizala, add="+")
        self.tv.bind("<Configure>",
                       lambda _e: self.root.after(60,
                                                    self._filtre_slotlarini_hizala),
                       add="+")

        # AI Açıklama / AI Karş. sütunlarında hover → tam içerik tooltip
        self._ai_tt_state = {"iid": None, "kod": None, "after_id": None,
                              "tip": None}
        self.tv.bind("<Motion>", self._ai_aciklama_hover, add="+")
        self.tv.bind("<Leave>", self._ai_aciklama_hover_leave, add="+")

        # ─────────── Yatay scroll senkronu (filtre + tablo birlikte) ───────────

        def _xview_birlikte(*args):
            self.tv.xview(*args)
            try:
                self._filtre_canvas.xview(*args)
            except Exception:
                pass
        xsb.configure(command=_xview_birlikte)

        def _on_tv_x_set(first, last):
            xsb.set(first, last)
            try:
                self._filtre_canvas.xview_moveto(float(first))
            except Exception:
                pass
        self.tv.configure(xscrollcommand=_on_tv_x_set)

        # Sütun yeniden boyutlandırma sonrası filtre slotlarını da güncellemek
        # için gecikmeli yenileme — başlık tıklamaları sonrası tetiklenir
        self._filtre_inner = filtre_inner
        self._filtre_slotlar = filtre_inner.winfo_children()
        self._filtre_h = FILTRE_H

    # ─────────────────────────────────────────────────────────────────
    # ATOMİK ŞART ŞEMASI PANELİ (sağ kolon, 1/3)
    # ─────────────────────────────────────────────────────────────────
    # Renkler: VAR yeşil, YOK kırmızı, KE turkuaz (mavi-yeşil arası), NA gri
    # KE rengi turkuaz (Teal 800/100) — eczacı kararı 2026-05-16: KE artık
    # mavi-yeşil arası, turuncudan farklı (turuncu = ŞÜPHELİ'nin verdict
    # rengiyle karışıyordu).
    _SEMA_DURUM_RENK = {
        "var": ("#1B5E20", "#E8F5E9", "✓"),
        "yok": ("#B71C1C", "#FFEBEE", "✗"),
        "kontrol_edilemedi": ("#00695C", "#B2DFDB", "?"),
        "na": ("#616161", "#ECEFF1", "—"),
    }
    _SEMA_SONUC_RENK = {
        "UYGUN": ("#1B5E20", "#C8E6C9"),                # koyu yeşil
        "UYGUN DEĞİL": ("#B71C1C", "#FFCDD2"),          # koyu kırmızı
        "ŞÜPHELİ": ("#E65100", "#FFE0B2"),              # turuncu
        # YENİ: ŞARTLI UYGUN — yeşil ile turuncu arası (limon)
        # eczacı şartı doğrulayınca UYGUN olur, doğrulayamazsa ŞÜPHELİ.
        "ŞARTLI UYGUN": ("#33691E", "#DCEDC8"),         # açık yeşil-zeytin
        "MANUEL KONTROL": ("#0D47A1", "#BBDEFB"),       # mavi
        "ATLANDI": ("#616161", "#ECEFF1"),              # gri
    }

    # Devre şeması renk pallet (kullanıcı isteği — yeşil/sarı/kırmızı/koyu gri)
    # YEŞİL = eşleşti (veri var ve uygun)
    # SARI  = şüpheli (KE — manuel doğrulama)
    # KIRMIZI = uygunsuz (AND zorunlu şart karşılanmıyor)
    # KOYU GRİ = eşleşmedi (VEYA grupta alternatif var, bu yol seçilmedi)
    # AÇIK GRİ = bilgi (manuel — hesap dışı)
    _DEVRE_RENK = {
        "var":    ("#66BB6A", "#1B5E20"),  # YEŞİL — eşleşti
        "yok":    ("#EF5350", "#B71C1C"),  # KIRMIZI — uygunsuz
        "or_yok": ("#757575", "#424242"),  # KOYU GRİ — eşleşmedi (alt yol)
        "ke":     ("#FFEE58", "#F57F17"),  # SARI — şüpheli
        "bilgi":  ("#E0E0E0", "#9E9E9E"),  # AÇIK GRİ — bilgi
    }
    _DEVRE_SEMBOL = {"var": "✓", "yok": "✗", "or_yok": "—",
                     "ke": "?", "bilgi": "i"}
    _DEVRE_KABLO_RENK = "#90A4AE"          # akımsız kablo (gri)
    _DEVRE_KABLO_W = 2
    _DEVRE_AKIM_RENK = "#43A047"           # akımlı kablo (yeşil, kalın)
    _DEVRE_AKIM_W = 4

    def _sema_kur(self, parent: tk.Frame) -> None:
        """Atomik şart paneli — yatay devre şeması (alt panel, sol⊕→sağ⊖).

        Başlıkta 3 toggle butonu: ▼ küçült (sadece başlık 50px) /
                                     ▬ normal (380px, tablonun 1/3'ü) /
                                     ▲ büyüt (600px, tablonun 1/2'si)
        """
        # Başlık + toggle butonları
        baslik = tk.Frame(parent, bg="#37474F", height=30)
        baslik.pack(side="top", fill="x")
        baslik.pack_propagate(False)
        tk.Label(baslik, text="📋",
                 bg="#37474F", fg="white",
                 font=("Segoe UI", 11, "bold")).pack(side="left", padx=(8, 4))

        # ── NAVİGASYON: ⬅ | X/Y | ➡ (kompakt) ─────────────────────────
        nav_btn_prev = tk.Button(
            baslik, text="⬅", bg="#455A64", fg="white",
            font=("Segoe UI", 9, "bold"),
            relief="flat", bd=0, padx=5, pady=1, cursor="hand2",
            command=lambda: self._sema_nav_recete(-1))
        nav_btn_prev.pack(side="left", padx=1, pady=3)
        _Tooltip(nav_btn_prev,
                  "Önceki reçete (filtrelenmiş satır üzerinde)\n"
                  "Kısayol: PageUp veya Alt+Sol")
        self._sema_panel_nav_lbl = tk.Label(
            baslik, text="—", bg="#37474F", fg="white",
            font=("Segoe UI", 9, "bold"), width=7)
        self._sema_panel_nav_lbl.pack(side="left", padx=1)
        nav_btn_next = tk.Button(
            baslik, text="➡", bg="#455A64", fg="white",
            font=("Segoe UI", 9, "bold"),
            relief="flat", bd=0, padx=5, pady=1, cursor="hand2",
            command=lambda: self._sema_nav_recete(+1))
        nav_btn_next.pack(side="left", padx=1, pady=3)
        _Tooltip(nav_btn_next,
                  "Sonraki reçete (filtrelenmiş satır üzerinde)\n"
                  "Kısayol: PageDown veya Alt+Sağ")

        # ── TEYİT: ✓ | ✗ | ? (kompakt sembol butonlar) ───────────────
        tk.Label(baslik, text="│", bg="#37474F", fg="#78909C",
                  font=("Segoe UI", 10)).pack(side="left", padx=(5, 2))
        btn_t1 = tk.Button(
            baslik, text="✓", bg="#2E7D32", fg="white",
            font=("Segoe UI", 10, "bold"),
            relief="flat", bd=0, padx=7, pady=1, cursor="hand2",
            command=lambda: self._ana_teyit_kaydet(
                recete_teyit_db.TEYIT_UYGUN))
        btn_t1.pack(side="left", padx=1, pady=3)
        _Tooltip(btn_t1,
                  "Seçili reçeteleri UYGUN olarak manuel teyit eder.\n"
                  "Tablodaki satır kalın yazı + ✓ rozeti ile işaretlenir.")
        btn_t2 = tk.Button(
            baslik, text="✗", bg="#B71C1C", fg="white",
            font=("Segoe UI", 10, "bold"),
            relief="flat", bd=0, padx=7, pady=1, cursor="hand2",
            command=lambda: self._ana_teyit_kaydet(
                recete_teyit_db.TEYIT_UYGUN_DEGIL))
        btn_t2.pack(side="left", padx=1, pady=3)
        _Tooltip(btn_t2,
                  "Seçili reçeteleri UYGUN DEĞİL olarak manuel teyit eder.\n"
                  "Tablodaki satır kalın yazı + ✗ rozeti ile işaretlenir.")
        btn_t3 = tk.Button(
            baslik, text="?", bg="#F9A825", fg="white",
            font=("Segoe UI", 10, "bold"),
            relief="flat", bd=0, padx=7, pady=1, cursor="hand2",
            command=lambda: self._ana_teyit_kaydet(
                recete_teyit_db.TEYIT_SUPHELI))
        btn_t3.pack(side="left", padx=1, pady=3)
        _Tooltip(btn_t3,
                  "Seçili reçeteleri ŞÜPHELİ olarak manuel teyit eder.\n"
                  "Tablodaki satır kalın yazı + ? rozeti ile işaretlenir.")
        # ⌫ — Tüm görünen satırların teyidini topluca sıfırla (kullanıcı isteği 2026-05-17)
        btn_t4 = tk.Button(
            baslik, text="⌫", bg="#546E7A", fg="white",
            font=("Segoe UI", 10, "bold"),
            relief="flat", bd=0, padx=7, pady=1, cursor="hand2",
            command=self._ana_teyit_kaldir_tumu)
        btn_t4.pack(side="left", padx=(4, 1), pady=3)
        _Tooltip(btn_t4,
                  "Görünen TÜM reçete satırlarının teyidini sıfırlar "
                  "(UYGUN / UYGUN DEĞİL / ŞÜPHELİ rozetlerini siler).\n"
                  "Filtre dışı satırlar etkilenmez.\n"
                  "İşlem öncesi onay sorulur.")

        # 🩺 MEDULA geçmiş rapor tarama — teyit butonlarının sağında
        btn_t_gecmis = tk.Button(
            baslik, text="🩺", bg="#4527A0", fg="white",
            font=("Segoe UI", 10, "bold"),
            relief="flat", bd=0, padx=7, pady=1, cursor="hand2",
            command=self._medula_gecmis_rapor_tara_baslat)
        btn_t_gecmis.pack(side="left", padx=(6, 1), pady=3)
        _Tooltip(btn_t_gecmis,
                  "🩺 MEDULA Geçmiş Raporlarını Tara\n\n"
                  "Seçili reçete satırındaki hastanın MEDULA'daki TÜM geçmiş\n"
                  "raporlarını yerel SQLite DB'ye tarar. Hepatit / diyabet /\n"
                  "KOAH kontrollerinde 'başlangıç raporu hangi tarihte' sorgusu\n"
                  "için kullanılır. SALT OKUMA.")

        # 🔍 Diğer Yolaklar toggle — dispatcher'ın elediği yolakları göster/gizle
        self._diger_yolak_panel_acik = False
        self._diger_yolak_btn = tk.Button(
            baslik, text="🔍 Diğer Yolaklar",
            bg="#37474F", fg="#FFCC80",
            font=("Segoe UI", 9, "bold"),
            relief="flat", bd=0, padx=8, pady=1, cursor="hand2",
            command=self._diger_yolaklar_toggle)
        self._diger_yolak_btn.pack(side="left", padx=(6, 1), pady=3)
        _Tooltip(self._diger_yolak_btn,
                  "🔍 Dispatcher'ın elediği diğer yolakları göster/gizle.\n\n"
                  "Aktif yolak şu an çizilen şemadır. Diğer 11 yolak için\n"
                  "(hepatit) eleme nedeni listesi açılır; bir başlığa\n"
                  "tıklayınca o yolağın atomları lazy hesaplanır ve\n"
                  "panelde görüntülenir.\n\n"
                  "Sadece hepatit modülünde aktif (diğer modüller için yapım aşamasında).")

        self._sema_panel_teyit_lbl = tk.Label(
            baslik, text="", bg="#37474F", fg="#FFEB3B",
            font=("Segoe UI", 8, "italic"))
        self._sema_panel_teyit_lbl.pack(side="left", padx=(4, 0))

        # Toggle butonları (sağda)
        for sembol, durum, ipucu in [("▼", "kucuk", "Küçült (sadece başlık)"),
                                       ("▬", "normal", "Normal (1/3)"),
                                       ("▲", "buyuk", "Büyüt (1/2)")]:
            btn = tk.Button(baslik, text=sembol,
                             bg="#455A64", fg="white",
                             font=("Segoe UI", 10, "bold"),
                             relief="flat", bd=0, padx=8, pady=2,
                             cursor="hand2",
                             command=lambda d=durum: self._sema_boyut_degistir(d))
            btn.pack(side="right", padx=2, pady=4)

        # Tam ekran toggle butonu (sağda, ilk sırada — daha belirgin renkte)
        tam_btn = tk.Button(baslik, text="⛶ Tam Ekran",
                              bg="#1565C0", fg="white",
                              font=("Segoe UI", 9, "bold"),
                              relief="flat", bd=0, padx=10, pady=2,
                              cursor="hand2",
                              command=self._sema_tam_ekran_toggle)
        tam_btn.pack(side="right", padx=(8, 4), pady=4)

        # Üst özet bandı — YATAY tek satır (yolak | sayım | sonuç)
        self._sema_ozet = tk.Frame(parent, bg="#FAFBFC", height=44)
        self._sema_ozet.pack(side="top", fill="x", padx=4, pady=(4, 0))
        self._sema_ozet.pack_propagate(False)

        # Notebook: 2 sekme — (D) DMN Karar Modeli, (G) Klasik Akım Şeması
        # Tab A/B/C/E/F kullanıcı tarafından kaldırıldı (snapshot: 3cd6b33).
        nb = ttk.Notebook(parent)
        nb.pack(side="top", fill="both", expand=True, padx=4, pady=4)
        self._sema_notebook = nb

        # ── TAB D: DMN Karar Modeli (OMG/HL7 FHIR CPG standardı) ──────
        # Decision Requirements Diagram (üst) + Decision Table (alt) +
        # Toulmin Rebuttal (en alt, sadece UYGUN_DEĞİL/ŞÜPHELİ'de görünür)
        # Pilot kapsam: YOAK SUT 4.2.15.D (D-1 AF / D-2 DVT-PE / EK-4/F)
        tab_dmn = tk.Frame(nb, bg="#FAFBFC")
        nb.add(tab_dmn, text="🎯 DMN Karar Modeli")

        self._dmn_canvas = tk.Canvas(tab_dmn, bg="white",
                                      highlightthickness=0)
        dmn_xsb = ttk.Scrollbar(tab_dmn, orient="horizontal",
                                 command=self._dmn_canvas.xview)
        dmn_xsb.pack(side="bottom", fill="x")
        dmn_ysb = ttk.Scrollbar(tab_dmn, orient="vertical",
                                 command=self._dmn_canvas.yview)
        dmn_ysb.pack(side="right", fill="y")
        self._dmn_canvas.pack(side="left", fill="both", expand=True)
        self._dmn_canvas.configure(xscrollcommand=dmn_xsb.set,
                                    yscrollcommand=dmn_ysb.set)

        self._dmn_neden_map = {}
        self._dmn_canvas.bind("<Motion>", self._dmn_canvas_hover)
        self._dmn_canvas.bind("<Leave>", lambda _e: self._sema_hide_tip())

        def _dmn_on_wheel(event):
            self._dmn_canvas.yview_scroll(int(-1 * (event.delta / 120)),
                                           "units")
        def _dmn_on_shift_wheel(event):
            self._dmn_canvas.xview_scroll(int(-1 * (event.delta / 120)),
                                           "units")
        self._dmn_canvas.bind("<MouseWheel>", _dmn_on_wheel)
        self._dmn_canvas.bind("<Shift-MouseWheel>", _dmn_on_shift_wheel)

        # ── TAB G: Klasik Akım Şeması (ampul + sade dikey paralel) ────
        # Tab F (RBD) ile aynı topoloji (dikey paralel + yatay seri) ama
        # kutu yerine ampul/lamba sembolü, kavşaklar düz paralel raylar
        # ("V" şeklinde değil), VE bağlantısı seri ana hat.
        tab_klasik = tk.Frame(nb, bg="#FAFBFC")
        nb.add(tab_klasik, text="🔆 Klasik Akım")

        # Zoom toolbar (üst) — Sığdır + 1:1
        self._klasik_zoom = 1.0
        zoom_bar = tk.Frame(tab_klasik, bg="#FAFBFC")
        zoom_bar.pack(side="top", fill="x", padx=4, pady=2)
        tk.Button(zoom_bar, text="🔍 Sığdır", relief="flat",
                   bg="#E3F2FD", fg="#0D47A1",
                   font=("Segoe UI", 8, "bold"),
                   command=self._klasik_zoom_sigdir).pack(side="left",
                                                            padx=(0, 4))
        tk.Button(zoom_bar, text="1:1 Yakınlaştır", relief="flat",
                   bg="#FFF3E0", fg="#E65100",
                   font=("Segoe UI", 8, "bold"),
                   command=self._klasik_zoom_birebir).pack(side="left")
        self._klasik_zoom_lbl = tk.Label(zoom_bar, text="(1.0x)",
                                          bg="#FAFBFC", fg="#90A4AE",
                                          font=("Segoe UI", 8))
        self._klasik_zoom_lbl.pack(side="left", padx=8)

        self._klasik_canvas = tk.Canvas(tab_klasik, bg="white",
                                          highlightthickness=0)
        klasik_xsb = ttk.Scrollbar(tab_klasik, orient="horizontal",
                                     command=self._klasik_canvas.xview)
        klasik_xsb.pack(side="bottom", fill="x")
        klasik_ysb = ttk.Scrollbar(tab_klasik, orient="vertical",
                                     command=self._klasik_canvas.yview)
        klasik_ysb.pack(side="right", fill="y")
        self._klasik_canvas.pack(side="left", fill="both", expand=True)
        self._klasik_canvas.configure(xscrollcommand=klasik_xsb.set,
                                        yscrollcommand=klasik_ysb.set)

        self._klasik_neden_map = {}
        self._klasik_canvas.bind("<Motion>", self._klasik_canvas_hover)
        self._klasik_canvas.bind("<Leave>", lambda _e: self._sema_hide_tip())

        def _klasik_on_wheel(event):
            self._klasik_canvas.yview_scroll(int(-1 * (event.delta / 120)),
                                               "units")
        def _klasik_on_shift_wheel(event):
            self._klasik_canvas.xview_scroll(int(-1 * (event.delta / 120)),
                                               "units")
        self._klasik_canvas.bind("<MouseWheel>", _klasik_on_wheel)
        self._klasik_canvas.bind("<Shift-MouseWheel>", _klasik_on_shift_wheel)

        # ── DİĞER YOLAKLAR PANELİ (varsayılan gizli, toggle ile açılır) ──
        # Üst panel'in altında ayrı bir frame; 🔍 toggle butonu pack/forget
        # eder. İçerik: sol Listbox (pasif yolak başlıkları + gerekçe) +
        # sağ ScrolledText (seçili yolağın atomları lazy hesaplanır).
        self._diger_yolak_frame = tk.Frame(parent, bg="#FFFDE7",
                                             height=200, bd=1, relief="solid")
        # NOT: ŞİMDİLİK pack ETMİYORUZ — toggle butonu ile açılır
        self._diger_yolak_frame.pack_propagate(False)

        # Başlık
        dy_baslik = tk.Frame(self._diger_yolak_frame, bg="#FFA000", height=24)
        dy_baslik.pack(side="top", fill="x")
        dy_baslik.pack_propagate(False)
        tk.Label(dy_baslik,
                  text="🔍 Dispatcher'ın Elediği Diğer Yolaklar (lazy hesaplama)",
                  bg="#FFA000", fg="white",
                  font=("Segoe UI", 9, "bold")).pack(side="left", padx=8)
        tk.Button(dy_baslik, text="✕", bg="#FFA000", fg="white",
                   font=("Segoe UI", 9, "bold"), relief="flat", bd=0,
                   padx=8, pady=0, cursor="hand2",
                   command=self._diger_yolaklar_toggle).pack(side="right")

        # İçerik: sol liste, sağ atomlar metni
        dy_govde = tk.Frame(self._diger_yolak_frame, bg="#FFFDE7")
        dy_govde.pack(side="top", fill="both", expand=True, padx=4, pady=4)

        sol = tk.Frame(dy_govde, bg="#FFFDE7", width=320)
        sol.pack(side="left", fill="y")
        sol.pack_propagate(False)
        self._diger_yolak_listbox = tk.Listbox(
            sol, font=("Segoe UI", 8), bg="white",
            selectmode="single", activestyle="dotbox")
        self._diger_yolak_listbox.pack(side="left", fill="both", expand=True)
        dy_ysb = ttk.Scrollbar(sol, orient="vertical",
                                command=self._diger_yolak_listbox.yview)
        dy_ysb.pack(side="right", fill="y")
        self._diger_yolak_listbox.configure(yscrollcommand=dy_ysb.set)
        self._diger_yolak_listbox.bind("<<ListboxSelect>>",
                                         self._diger_yolaklar_secim)

        sag = tk.Frame(dy_govde, bg="#FFFDE7")
        sag.pack(side="left", fill="both", expand=True, padx=(6, 0))
        self._diger_yolak_text = tk.Text(
            sag, font=("Consolas", 9), bg="white", wrap="word",
            height=10, state="disabled")
        self._diger_yolak_text.pack(side="left", fill="both", expand=True)
        dy_xsb = ttk.Scrollbar(sag, orient="vertical",
                                command=self._diger_yolak_text.yview)
        dy_xsb.pack(side="right", fill="y")
        self._diger_yolak_text.configure(yscrollcommand=dy_xsb.set)

        # Veri ön belleği: aktif satırın diger_yolaklar listesi + ilac_sonuc
        self._diger_yolak_aktif_satir: Optional[Dict] = None
        self._diger_yolak_aktif_liste: List[Dict] = []

        self._sema_temizle("Bir reçete satırı seçin")

    # ─────────────────────────────────────────────────────────────────
    # KONTROL BUTONLARI POPUP — 15 buton tek bir popup grid'inde
    # ─────────────────────────────────────────────────────────────────
    def _kontrol_butonlari_topla(self) -> list:
        """Gizli buton frame'lerinden tüm Button widget'larını topla.

        Returns: List[(text, bg, button_widget)] — invoke için widget kendisi.
        """
        butonlar = []
        for frame_attr in ("_row_kontrol_btn", "_row_sut_btn",
                            "_row_diger_btn", "_row_diger2_btn"):
            f = getattr(self, frame_attr, None)
            if f is None:
                continue
            for ch in f.winfo_children():
                if isinstance(ch, tk.Button):
                    try:
                        butonlar.append((ch.cget("text"),
                                          ch.cget("bg"), ch))
                    except Exception:
                        pass
        return butonlar

    def _kontrol_butonlari_popup_ac(self) -> None:
        """Popup pencere açar — 15 SUT/uyarı butonunu 3×5 grid'de gösterir."""
        try:
            butonlar = self._kontrol_butonlari_topla()
        except Exception as e:
            butonlar = []
        if not butonlar:
            try:
                from tkinter import messagebox
                messagebox.showinfo("Kontrol Butonları",
                                     "Henüz buton yüklenmemiş.", parent=self.root)
            except Exception:
                pass
            return

        pop = tk.Toplevel(self.root)
        pop.title("🎯 Kontrol Butonları")
        pop.configure(bg="#FAFBFC")
        pop.transient(self.root)
        # Pencere boyutu: butona göre dinamik (3x5 = ~860x320)
        n = len(butonlar)
        sutun = 5
        satir = (n + sutun - 1) // sutun
        pop.geometry(f"{160 * sutun + 40}x{60 * satir + 100}")

        # Üstte "TÜMÜ" butonu
        tk.Button(pop, text="🎯  TÜMÜNÜ KONTROL ET (15 buton sırayla)",
                   bg="#1A237E", fg="white",
                   font=("Segoe UI", 11, "bold"),
                   activebackground="#283593",
                   relief="flat", bd=0, padx=20, pady=10, cursor="hand2",
                   command=lambda: self._kontrol_tumunu_calistir(pop)
                   ).pack(side="top", fill="x", padx=8, pady=(8, 4))

        tk.Label(pop, text="—— veya tek bir kontrol seç ——",
                 bg="#FAFBFC", fg="#90A4AE",
                 font=("Segoe UI", 8, "italic")
                 ).pack(side="top", pady=(4, 6))

        # Grid alanı
        grid_frame = tk.Frame(pop, bg="#FAFBFC")
        grid_frame.pack(side="top", fill="both", expand=True, padx=8, pady=4)

        for i, (text, bg, widget) in enumerate(butonlar):
            r, col = divmod(i, sutun)
            try:
                fg = widget.cget("fg")
            except Exception:
                fg = "white"
            b = tk.Button(grid_frame, text=text,
                           bg=bg, fg=fg,
                           font=("Segoe UI", 9, "bold"),
                           activebackground=bg,
                           relief="flat", bd=0, padx=4, pady=10,
                           cursor="hand2", wraplength=140,
                           command=lambda w=widget, p=pop:
                               self._kontrol_buton_secildi(w, p))
            b.grid(row=r, column=col, padx=3, pady=3, sticky="nsew")

        for col in range(sutun):
            grid_frame.columnconfigure(col, weight=1, uniform="kontrol")
        for r in range(satir):
            grid_frame.rowconfigure(r, weight=1)

        # Klavye: Esc kapatır
        pop.bind("<Escape>", lambda _e: pop.destroy())
        pop.focus_set()

    def _kontrol_buton_secildi(self, widget: tk.Button,
                                 popup: tk.Toplevel) -> None:
        """Popup'tan bir buton seçildiğinde — popup'ı kapat + butonu invoke et.

        Çift tıklama koruması: aynı butonun art arda iki kez çağrılmasını
        engeller (yoksa 2 Excel raporu üretilir).
        """
        if getattr(self, "_kontrol_calistiriliyor", False):
            return
        self._kontrol_calistiriliyor = True
        try:
            popup.destroy()
        except Exception:
            pass

        def _calistir_ve_resetle():
            try:
                widget.invoke()
            finally:
                # Bir sonraki kontrol için flag'i sıfırla
                self._kontrol_calistiriliyor = False
        try:
            self.root.after(80, _calistir_ve_resetle)
        except Exception:
            self._kontrol_calistiriliyor = False

    def _kontrol_tumunu_calistir(self, popup: tk.Toplevel) -> None:
        """TÜMÜ butonu — tüm kontrolleri sırayla çalıştırır."""
        try:
            popup.destroy()
        except Exception:
            pass
        butonlar = self._kontrol_butonlari_topla()
        # Her butonu sırayla invoke et (yeterince gecikmeli — UI bloklamasın)
        gecikme = 100
        for i, (_text, _bg, widget) in enumerate(butonlar):
            try:
                self.root.after(gecikme + i * 80, widget.invoke)
            except Exception:
                pass

    def _pasif_detay_toggle(self) -> None:
        """Pasif yolak gösterimini aç/kapat: özet ↔ detaylı."""
        self._sema_pasif_detayli = not getattr(self, "_sema_pasif_detayli",
                                                 False)
        self.root.after(80, self._sema_secim_guncelle)

    def _aktif_detay_toggle(self) -> None:
        """Aktif yolak gösterimini aç/kapat: özet ↔ detaylı.

        Default detaylı (tüm gruplar görünür); kapatılınca tek özet ampul
        + sayım — pasif yolaktaki davranışın aynısı.
        """
        self._sema_aktif_detayli = not getattr(self, "_sema_aktif_detayli",
                                                 True)
        self.root.after(80, self._sema_secim_guncelle)

    def _grup_detay_toggle(self, grup_ad: str) -> None:
        """Paralel grup için özet/detay aç-kapa (varsayılan: özet)."""
        if not hasattr(self, "_sema_grup_detayli"):
            self._sema_grup_detayli = set()
        if grup_ad in self._sema_grup_detayli:
            self._sema_grup_detayli.discard(grup_ad)
        else:
            self._sema_grup_detayli.add(grup_ad)
        self.root.after(80, self._sema_secim_guncelle)

    def _bilgi_toggle(self) -> None:
        """Manuel doğrulama listesi aç-kapa (varsayılan: kapalı)."""
        self._sema_bilgi_acik = not getattr(self, "_sema_bilgi_acik", False)
        self.root.after(80, self._sema_secim_guncelle)

    def _klasik_zoom_sigdir(self) -> None:
        """Tab G canvas içeriğini görüntü alanına sığacak şekilde küçült.
        Mevcut bbox'ı canvas widget boyutuna göre orantıla, yeni zoom
        faktörünü hesapla, re-render et."""
        c = getattr(self, '_klasik_canvas', None)
        if c is None:
            return
        bbox = c.bbox("klasik")
        if not bbox:
            return
        c.update_idletasks()
        cw = max(c.winfo_width(), 100)
        ch = max(c.winfo_height(), 100)
        icerik_w = max(bbox[2] - bbox[0], 10)
        icerik_h = max(bbox[3] - bbox[1], 10)
        # Mevcut zoom ile birlikte hesapla — sığdırma absolute zoom verir
        sx = (cw - 30) / icerik_w
        sy = (ch - 30) / icerik_h
        yeni_zoom = max(0.25, min(1.0, self._klasik_zoom * min(sx, sy)))
        self._klasik_zoom = yeni_zoom
        self._klasik_zoom_lbl.config(text=f"({yeni_zoom:.2f}x)")
        # Re-render
        satir = self._aktif_satir() if callable(getattr(self, '_aktif_satir',
                                                          None)) else None
        if satir:
            self._sema_render(satir)

    def _klasik_zoom_birebir(self) -> None:
        """Tab G zoom'u 1.0x'e döndür (varsayılan boyut)."""
        self._klasik_zoom = 1.0
        if hasattr(self, '_klasik_zoom_lbl'):
            self._klasik_zoom_lbl.config(text="(1.0x)")
        satir = self._aktif_satir() if callable(getattr(self, '_aktif_satir',
                                                          None)) else None
        if satir:
            self._sema_render(satir)

    def _sema_boyut_degistir(self, durum: str) -> None:
        """Şema panelinin yüksekliğini değiştir (kucuk/normal/buyuk).

        kucuk: sadece başlık (50px) — devre gizlenir
        normal: 380px (tablonun 1/3'ü)
        buyuk: 600px (tablonun 1/2'si)
        """
        if not hasattr(self, "_sema_yukseklikler"):
            return
        yeni_h = self._sema_yukseklikler.get(durum, 380)
        self._sema_durum = durum
        try:
            self.sema_frame.configure(height=yeni_h)
        except Exception:
            pass
        # Render'ı yeni yüksekliğe göre tekrar çiz
        self.root.after(120, self._sema_secim_guncelle)

    def _sema_tam_ekran_toggle(self) -> None:
        """Atomik şema paneli için tam ekran toggle.

        Yeni bir Toplevel açar, içinde DMN + Klasik sekmelerini büyük
        canvas'larla render eder. ESC veya '✕ Kapat' ile geri döner.
        Render aynı kod yolunu kullanır — sadece canvas referansları
        geçici olarak swap edilir; kapanışta orijinal canvas'lar geri
        yüklenir ve sema_secim_guncelle çağrılır.
        """
        import tkinter as tk
        from tkinter import ttk
        # Zaten açıksa kapat
        top = getattr(self, '_sema_tam_top', None)
        if top is not None and top.winfo_exists():
            try:
                self._klasik_canvas = self._sema_tam_orig_klasik
                self._dmn_canvas = self._sema_tam_orig_dmn
                # Zoom seviyesini geri yükle
                if hasattr(self, '_sema_tam_orig_zoom'):
                    self._klasik_zoom = self._sema_tam_orig_zoom
            except Exception:
                pass
            try:
                top.destroy()
            except Exception:
                pass
            self._sema_tam_top = None
            # Tam ekrana özel widget referanslarını temizle
            self._sema_tam_nav_lbl = None
            self._sema_tam_teyit_lbl = None
            self.root.after(120, self._sema_secim_guncelle)
            return

        # Toplevel oluştur, fullscreen
        top = tk.Toplevel(self.root)
        top.title("📋 Atomik SUT Devre Şeması — Tam Ekran (ESC ile kapat)")
        try:
            top.state('zoomed')  # Windows: maximize
        except Exception:
            try:
                top.attributes('-fullscreen', True)
            except Exception:
                pass
        top.bind('<Escape>', lambda e: self._sema_tam_ekran_toggle())
        top.protocol("WM_DELETE_WINDOW", self._sema_tam_ekran_toggle)
        self._sema_tam_top = top

        # Üst banner — başlık + zoom kontrolleri + kapat butonu
        header = tk.Frame(top, bg="#1565C0", height=44)
        header.pack(side="top", fill="x")
        header.pack_propagate(False)
        tk.Label(header,
                  text="📋  Atomik SUT Devre Şeması",
                  bg="#1565C0", fg="white",
                  font=("Segoe UI", 11, "bold")).pack(side="left", padx=(14, 8))

        # ── NAVİGASYON: ⬅ Önceki | sayaç | Sonraki ➡ ──────────────────
        nav_frame = tk.Frame(header, bg="#1565C0")
        nav_frame.pack(side="left", padx=(8, 6))
        tk.Button(nav_frame, text="⬅ Önceki",
                   bg="#0D47A1", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=lambda: self._sema_nav_recete(-1)
                   ).pack(side="left", padx=2)
        self._sema_tam_nav_lbl = tk.Label(
            nav_frame, text="—", bg="#1565C0", fg="white",
            font=("Segoe UI", 10, "bold"), width=14)
        self._sema_tam_nav_lbl.pack(side="left", padx=4)
        tk.Button(nav_frame, text="Sonraki ➡",
                   bg="#0D47A1", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=lambda: self._sema_nav_recete(+1)
                   ).pack(side="left", padx=2)

        # Klavye kısayolları (PageUp/PageDown + Alt+Sol/Sağ)
        top.bind('<Prior>', lambda e: self._sema_nav_recete(-1))
        top.bind('<Next>', lambda e: self._sema_nav_recete(+1))
        top.bind('<Alt-Left>', lambda e: self._sema_nav_recete(-1))
        top.bind('<Alt-Right>', lambda e: self._sema_nav_recete(+1))

        # Sağ tık: tam ekran şemada da ana tablodaki context menüsü açılır.
        # _sag_tik_menu zaten event.x_root/y_root kullandığı için ve aktif
        # satırı self.tv.selection() üzerinden okuduğu için ekstra düzenleme
        # gerekmez — şema açıkken zaten o satır seçilidir.
        top.bind('<Button-3>', self._sag_tik_menu_tam_ekran)

        # ── TEYİT: ✓ UYGUN | ✗ UYGUN DEĞİL | ? ŞÜPHELİ ────────────────
        ayrac = tk.Label(header, text="│", bg="#1565C0", fg="#90CAF9",
                          font=("Segoe UI", 14))
        ayrac.pack(side="left", padx=(6, 6))
        tk.Label(header, text="Teyit:",
                  bg="#1565C0", fg="white",
                  font=("Segoe UI", 10, "bold")).pack(side="left", padx=(0, 4))
        teyit_frame = tk.Frame(header, bg="#1565C0")
        teyit_frame.pack(side="left", padx=2)
        tk.Button(teyit_frame, text="✓ UYGUN",
                   bg="#2E7D32", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=lambda: self._sema_teyit_kaydet(
                       recete_teyit_db.TEYIT_UYGUN)
                   ).pack(side="left", padx=2)
        tk.Button(teyit_frame, text="✗ UYGUN DEĞİL",
                   bg="#B71C1C", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=lambda: self._sema_teyit_kaydet(
                       recete_teyit_db.TEYIT_UYGUN_DEGIL)
                   ).pack(side="left", padx=2)
        tk.Button(teyit_frame, text="? ŞÜPHELİ",
                   bg="#F9A825", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=lambda: self._sema_teyit_kaydet(
                       recete_teyit_db.TEYIT_SUPHELI)
                   ).pack(side="left", padx=2)
        # 🩺 MEDULA geçmiş rapor tarama — teyit butonlarının sağında
        btn_gecmis_tam = tk.Button(teyit_frame, text="🩺 GEÇMİŞ TARA",
                   bg="#4527A0", fg="white",
                   activebackground="#311B92",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=self._medula_gecmis_rapor_tara_baslat)
        btn_gecmis_tam.pack(side="left", padx=(10, 2))
        _Tooltip(btn_gecmis_tam,
                  "Seçili hastanın MEDULA'daki TÜM geçmiş raporlarını yerel\n"
                  "SQLite DB'ye tarar. Hepatit / diyabet / KOAH kontrolleri\n"
                  "'başlangıç raporu hangi tarihte' sorgusu için kullanır.\n\n"
                  "CLAUDE.md: SALT OKUMA — MEDULA verisi değiştirilmez.")
        # Teyit durum etiketi (mevcut kayıt göstergesi)
        self._sema_tam_teyit_lbl = tk.Label(
            header, text="", bg="#1565C0", fg="#FFEB3B",
            font=("Segoe UI", 9, "italic"))
        self._sema_tam_teyit_lbl.pack(side="left", padx=(8, 0))

        # ── ZOOM KONTROLLERİ (Sığdır / 1:1 / + / − / zoom göstergesi) ──
        tk.Button(header, text="✕  Kapat",
                   bg="#B71C1C", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=14, pady=4,
                   cursor="hand2",
                   command=self._sema_tam_ekran_toggle
                   ).pack(side="right", padx=10, pady=6)

        # Zoom buton kümesi (sağdan başlayarak)
        # Zoom göstergesi label
        zoom_lbl_full = tk.Label(header, text="(1.4x)",
                                   bg="#1565C0", fg="white",
                                   font=("Segoe UI", 10, "bold"))
        zoom_lbl_full.pack(side="right", padx=(6, 12), pady=8)

        # +/- butonları (zoom adım: ±0.15)
        def _zoom_adim(d):
            yeni = max(0.4, min(3.0, self._klasik_zoom + d))
            self._klasik_zoom = yeni
            try:
                zoom_lbl_full.config(text=f"({yeni:.2f}x)")
            except Exception:
                pass
            self.root.after(50, self._sema_secim_guncelle)

        tk.Button(header, text="＋",
                   bg="#0D47A1", fg="white",
                   font=("Segoe UI", 11, "bold"),
                   relief="flat", bd=0, padx=10, pady=2,
                   cursor="hand2",
                   command=lambda: _zoom_adim(+0.15)
                   ).pack(side="right", padx=2, pady=6)
        tk.Button(header, text="−",
                   bg="#0D47A1", fg="white",
                   font=("Segoe UI", 11, "bold"),
                   relief="flat", bd=0, padx=12, pady=2,
                   cursor="hand2",
                   command=lambda: _zoom_adim(-0.15)
                   ).pack(side="right", padx=2, pady=6)

        # 1:1 Yakınlaştır (zoom 1.0x)
        def _zoom_birebir_full():
            self._klasik_zoom = 1.0
            try:
                zoom_lbl_full.config(text="(1.00x)")
            except Exception:
                pass
            self.root.after(50, self._sema_secim_guncelle)
        tk.Button(header, text="1:1",
                   bg="#0D47A1", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=10, pady=4,
                   cursor="hand2",
                   command=_zoom_birebir_full
                   ).pack(side="right", padx=2, pady=6)

        # Sığdır — fullscreen canvas içine içeriği sığdır
        def _zoom_sigdir_full():
            # Mevcut _klasik_zoom_sigdir mantığı (Toplevel canvas'a uyumlu)
            c = self._klasik_canvas  # şu an Toplevel'in canvas'ı (swap edildi)
            try:
                bbox = c.bbox("klasik")
                if not bbox:
                    return
                c.update_idletasks()
                cw = max(c.winfo_width(), 100)
                ch = max(c.winfo_height(), 100)
                icerik_w = max(bbox[2] - bbox[0], 10)
                icerik_h = max(bbox[3] - bbox[1], 10)
                sx = (cw - 30) / icerik_w
                sy = (ch - 30) / icerik_h
                # Tam ekran modunda 3.0x'e kadar büyütebilsin
                yeni_zoom = max(0.25, min(3.0,
                                           self._klasik_zoom * min(sx, sy)))
                self._klasik_zoom = yeni_zoom
                try:
                    zoom_lbl_full.config(text=f"({yeni_zoom:.2f}x)")
                except Exception:
                    pass
                self.root.after(50, self._sema_secim_guncelle)
            except Exception:
                pass
        tk.Button(header, text="🔍 Sığdır",
                   bg="#0D47A1", fg="white",
                   font=("Segoe UI", 10, "bold"),
                   relief="flat", bd=0, padx=12, pady=4,
                   cursor="hand2",
                   command=_zoom_sigdir_full
                   ).pack(side="right", padx=(12, 4), pady=6)

        # Fullscreen-local zoom label'ı saklayıp orijinal _klasik_zoom_lbl ile
        # eşitleyelim — böylece _klasik_zoom_sigdir/birebir çağrıları da
        # fullscreen label'ı günceller (orijinal label da güncellenir ama
        # gizli olduğu için sorun değil).
        self._sema_tam_zoom_lbl = zoom_lbl_full

        # ── Hasta/reçete/rapor bilgi şeridi (kullanıcı isteği 2026-05-17:
        # yataya yayılı; sol=reçete (mavi) + sağ=rapor (sarı). Uzun veri
        # gelirse Label wraplength sayesinde alt satıra geçer; hala sığmazsa
        # mouse hover ile tooltip'te tam metin görünür.
        info_bar = tk.Frame(top, bg="#E3F2FD")
        info_bar.pack(side="top", fill="x")
        # pack_propagate(True) — Frame, içerik kadar (2 satır veya gerekirse
        # 3-5 satır) yükselir. Kullanıcı kuralı 2026-05-17: okunamamazlık olmasın.

        # SOL — Reçete bloğu (mavi)
        info_sol = tk.Frame(info_bar, bg="#E3F2FD")
        info_sol.pack(side="left", fill="both", expand=True,
                       padx=(8, 2), pady=3)
        tk.Label(info_sol, text="📋 REÇETE",
                  bg="#E3F2FD", fg="#01579B",
                  font=("Segoe UI", 8, "bold"),
                  anchor="w").pack(fill="x")
        # wraplength: dar pencerede otomatik alt satır.
        # Sema penceresi tam ekran (~1900 px) → her blok ~940 px.
        self._sema_tam_info_rec_lbl = tk.Label(
            info_sol, text="(reçete seçilmedi)",
            bg="#E3F2FD", fg="#0D47A1",
            font=("Segoe UI", 9, "bold"),
            anchor="nw", justify="left",
            wraplength=900)
        self._sema_tam_info_rec_lbl.pack(fill="both", expand=True)

        # Ayırıcı dikey çizgi
        tk.Frame(info_bar, bg="#90CAF9", width=2).pack(
            side="left", fill="y", pady=4)

        # SAĞ — Rapor bloğu (sarı — RaporAna alanı rengi)
        info_sag = tk.Frame(info_bar, bg="#FFF8E1")
        info_sag.pack(side="left", fill="both", expand=True,
                       padx=(2, 8), pady=3)
        tk.Label(info_sag, text="📄 RAPOR",
                  bg="#FFF8E1", fg="#E65100",
                  font=("Segoe UI", 8, "bold"),
                  anchor="w").pack(fill="x")
        self._sema_tam_info_rap_lbl = tk.Label(
            info_sag, text="",
            bg="#FFF8E1", fg="#5D4037",
            font=("Segoe UI", 9, "bold"),
            anchor="nw", justify="left",
            wraplength=900)
        self._sema_tam_info_rap_lbl.pack(fill="both", expand=True)

        # Pencere boyu değişince wraplength'i dinamik ayarla — pencere küçülürse
        # metin daha çok satıra sarar, büyürse tek satır.
        def _info_resize(_ev=None):
            try:
                w = info_bar.winfo_width()
                if w < 200:
                    return
                # Her panel ~ (toplam - 20 padding - 2 ayırıcı) / 2
                yari = max(300, (w - 22) // 2)
                self._sema_tam_info_rec_lbl.config(wraplength=yari)
                self._sema_tam_info_rap_lbl.config(wraplength=yari)
            except Exception:
                pass
        info_bar.bind("<Configure>", _info_resize)

        # Geriye uyumluluk — eski koda dokunmayan _sema_tam_info_lbl alias
        # (yeni kod sol bloğa yazar; eski _sema_tam_bilgi_guncelle çağırımları
        # alttaki güncel implementasyona düşer).
        self._sema_tam_info_lbl = self._sema_tam_info_rec_lbl

        # Tooltip — hover ile tam (kırpılmamış) metin görünür.
        # _Tooltip text mutable; _sema_tam_bilgi_guncelle her güncellemede
        # self._sema_tam_tt_rec.text / .text yeniden atar.
        self._sema_tam_tt_rec = _Tooltip(
            self._sema_tam_info_rec_lbl, "(reçete seçilmedi)", delay_ms=600)
        self._sema_tam_tt_rap = _Tooltip(
            self._sema_tam_info_rap_lbl, "", delay_ms=600)

        # Sağ tık menüsü — her iki blok da
        for w in (info_bar, info_sol, info_sag,
                   self._sema_tam_info_rec_lbl, self._sema_tam_info_rap_lbl):
            w.bind("<Button-3>", self._sag_tik_menu_tam_ekran)

        # Notebook — DMN + Klasik
        nb = ttk.Notebook(top)
        nb.pack(fill="both", expand=True, padx=6, pady=6)

        # DMN canvas + scrollbarlar
        tab_dmn = tk.Frame(nb, bg="#FAFBFC")
        nb.add(tab_dmn, text="🎯 DMN Karar Modeli")
        dmn_wrap = tk.Frame(tab_dmn)
        dmn_wrap.pack(fill="both", expand=True)
        dmn_v = tk.Scrollbar(dmn_wrap, orient="vertical")
        dmn_h = tk.Scrollbar(dmn_wrap, orient="horizontal")
        big_dmn = tk.Canvas(dmn_wrap, bg="white", highlightthickness=0,
                              yscrollcommand=dmn_v.set,
                              xscrollcommand=dmn_h.set)
        dmn_v.config(command=big_dmn.yview)
        dmn_h.config(command=big_dmn.xview)
        dmn_v.pack(side="right", fill="y")
        dmn_h.pack(side="bottom", fill="x")
        big_dmn.pack(side="left", fill="both", expand=True)
        big_dmn.bind("<Motion>", self._dmn_canvas_hover)
        big_dmn.bind("<Leave>", lambda _e: self._sema_hide_tip())
        big_dmn.bind("<Button-3>", self._sag_tik_menu_tam_ekran)

        # Klasik canvas + scrollbarlar
        tab_klasik = tk.Frame(nb, bg="#FAFBFC")
        nb.add(tab_klasik, text="🔆 Klasik Akım Şeması")
        klasik_wrap = tk.Frame(tab_klasik)
        klasik_wrap.pack(fill="both", expand=True)
        klasik_v = tk.Scrollbar(klasik_wrap, orient="vertical")
        klasik_h = tk.Scrollbar(klasik_wrap, orient="horizontal")
        big_klasik = tk.Canvas(klasik_wrap, bg="white", highlightthickness=0,
                                yscrollcommand=klasik_v.set,
                                xscrollcommand=klasik_h.set)
        klasik_v.config(command=big_klasik.yview)
        klasik_h.config(command=big_klasik.xview)
        klasik_v.pack(side="right", fill="y")
        klasik_h.pack(side="bottom", fill="x")
        big_klasik.pack(side="left", fill="both", expand=True)
        big_klasik.bind("<Motion>", self._klasik_canvas_hover)
        big_klasik.bind("<Leave>", lambda _e: self._sema_hide_tip())
        big_klasik.bind("<Button-3>", self._sag_tik_menu_tam_ekran)

        # Klasik akış için tab'a geç (kullanıcının bekleyeceği görünüm)
        nb.select(tab_klasik)

        # Canvas referanslarını geçici olarak swap et
        self._sema_tam_orig_klasik = self._klasik_canvas
        self._sema_tam_orig_dmn = self._dmn_canvas
        self._klasik_canvas = big_klasik
        self._dmn_canvas = big_dmn

        # Tam ekran zoom'u biraz arttır (büyük canvas için 1.4x default)
        self._sema_tam_orig_zoom = getattr(self, '_klasik_zoom', 1.0)
        self._klasik_zoom = 1.4

        # Render — yeni canvas'a çiz
        self.root.after(150, self._sema_secim_guncelle)

    # ─────────────────────────────────────────────────────────────────
    # TAM EKRAN ŞEMA — NAVİGASYON + TEYİT (filtrelenmiş satırlar arası)
    # ─────────────────────────────────────────────────────────────────
    def _sema_nav_recete(self, yon: int) -> None:
        """Tam ekran şemada filtrelenmiş satırlar arasında gezin.

        yon: -1 önceki, +1 sonraki
        Filtrelenmiş+görünen satırlar tv.get_children() ile alınır;
        uçlara gelince clamp (wrap-around yapmaz).
        """
        try:
            cocuklar = list(self.tv.get_children())
        except Exception:
            cocuklar = []
        if not cocuklar:
            return
        sec = self.tv.selection()
        if sec:
            try:
                idx = cocuklar.index(sec[0])
            except ValueError:
                idx = -1 if yon > 0 else len(cocuklar)
        else:
            idx = -1 if yon > 0 else len(cocuklar)
        yeni = idx + yon
        if yeni < 0:
            yeni = 0
        elif yeni >= len(cocuklar):
            yeni = len(cocuklar) - 1
        if yeni == idx:
            return  # uçtayız, hareket yok
        yeni_iid = cocuklar[yeni]
        try:
            self.tv.selection_set(yeni_iid)
            self.tv.focus(yeni_iid)
            self.tv.see(yeni_iid)
        except Exception:
            pass
        # <<TreeviewSelect>> otomatik _sema_secim_guncelle tetikler;
        # yine de güvenli yan: after ile gecikmeli çağrı
        self.root.after(40, self._sema_secim_guncelle)

    def _sema_nav_lbl_guncelle(self) -> None:
        """'Reçete X / Y' sayaç label'larını güncelle (panel + tam ekran)."""
        try:
            cocuklar = list(self.tv.get_children())
            toplam = len(cocuklar)
            sec = self.tv.selection()
            if sec:
                try:
                    idx = cocuklar.index(sec[0]) + 1
                except ValueError:
                    idx = 0
            else:
                idx = 0
            metin_kisa = f"{idx}/{toplam}"
            metin_uzun = f"Reçete {idx} / {toplam}"
            for lbl, metin in (
                (getattr(self, '_sema_panel_nav_lbl', None), metin_kisa),
                (getattr(self, '_sema_tam_nav_lbl', None), metin_uzun),
            ):
                if lbl is None:
                    continue
                try:
                    lbl.config(text=metin)
                except Exception:
                    pass
        except Exception:
            pass

    def _sema_teyit_lbl_guncelle(self, satir: dict | None = None) -> None:
        """Teyit durum label'larını güncelle (panel + tam ekran)."""
        kisa = ""   # gömülü panel için — yer dar
        uzun = ""   # tam ekran için — geniş
        try:
            if satir is not None:
                ri_id = str(satir.get("ri_id") or "")
                kayit = recete_teyit_db.teyit_oku(ri_id)
                if kayit:
                    etiket = recete_teyit_db.ETIKET.get(
                        kayit.get("teyit_sonucu") or "", "")
                    tarih = (kayit.get("tarih") or "")[:16].replace("T", " ")
                    kullanici = kayit.get("kullanici") or ""
                    kisa = etiket
                    parcalar = [etiket]
                    if tarih:
                        parcalar.append(tarih)
                    if kullanici:
                        parcalar.append(kullanici)
                    uzun = "  ·  ".join(p for p in parcalar if p)
                else:
                    kisa = ""
                    uzun = "(teyit yok)"
        except Exception:
            pass
        for lbl, metin in (
            (getattr(self, '_sema_panel_teyit_lbl', None), kisa),
            (getattr(self, '_sema_tam_teyit_lbl', None), uzun),
        ):
            if lbl is None:
                continue
            try:
                lbl.config(text=metin)
            except Exception:
                pass

    def _recetenin_tum_iidleri(self, kaynak_iid: str) -> list:
        """Verilen iid'nin ait olduğu reçetenin tüm ilaç satırı iid'lerini döndür.

        Grup anahtarı: rec_no (RxSgkIslemNo) öncelikli, fallback sistem_recete_no.
        Reçete numarası belirlenemezse sadece kaynak iid döner.
        """
        kaynak = self.satir_indeks.get(str(kaynak_iid))
        if not kaynak:
            return [str(kaynak_iid)]
        rec_no = str(kaynak.get("rec_no") or "").strip()
        sis_no = str(kaynak.get("sistem_recete_no") or "").strip()
        if not rec_no and not sis_no:
            return [str(kaynak_iid)]
        iids = []
        for s in self.tum_satirlar:
            s_rec = str(s.get("rec_no") or "").strip()
            s_sis = str(s.get("sistem_recete_no") or "").strip()
            if (rec_no and s_rec == rec_no) or (sis_no and s_sis == sis_no):
                iids.append(str(s["ri_id"]))
        return iids or [str(kaynak_iid)]

    def _sema_teyit_kaydet(self, teyit_sonucu: str) -> None:
        """Aktif reçete için teyiti DB'ye yaz, tabloyu güncelle.

        Kullanıcı ayarı: aynı reçetede kal (oto-ilerleme yok),
        son teyit geçerli (üzerine yaz). Teyit sonucuna karşılık gelen renk
        (UYGUN=yeşil / ŞÜPHELİ=sarı / UYGUN DEĞİL=kırmızı) reçetenin
        TÜM ilaç satırlarına uygulanır.
        """
        satir = self._aktif_satir()
        if not satir:
            try:
                messagebox.showwarning(
                    "Teyit",
                    "Önce bir reçete satırı seçin.",
                    parent=getattr(self, '_sema_tam_top', None) or self.root,
                )
            except Exception:
                pass
            return
        ri_id = str(satir.get("ri_id") or "")
        kullanici = self._aktif_kullanici_adi()
        yeni_renk = TEYIT_RENK.get(teyit_sonucu, RENK_BEYAZ)
        grup_iidler = self._recetenin_tum_iidleri(ri_id)
        if not hasattr(self, "_teyit_map") or self._teyit_map is None:
            self._teyit_map = {}
        basarili = 0
        for g_iid in grup_iidler:
            g_satir = self.satir_indeks.get(g_iid)
            if not g_satir:
                continue
            ok = recete_teyit_db.teyit_kaydet(
                g_iid,
                teyit_sonucu,
                hasta_tc=str(g_satir.get("tc") or ""),
                recete_no=str(g_satir.get("rec_no") or ""),
                ilac_adi=str(g_satir.get("ilac") or ""),
                sut_kategorisi=str(g_satir.get("sut") or ""),
                kullanici=kullanici,
                otomatik_sonuc=str(g_satir.get("verdict") or ""),
            )
            if not ok:
                continue
            self._teyit_map[g_iid] = teyit_sonucu
            g_satir["teyit"] = recete_teyit_db.rozet(teyit_sonucu)
            self.satir_renkleri[g_iid] = yeni_renk
            try:
                values = tuple(str(g_satir.get(k, "")) for k in SUTUN_KOD)
                self.tv.item(g_iid, values=values,
                             tags=(yeni_renk, "teyit_bold"))
            except Exception:
                pass
            basarili += 1
        if not basarili:
            try:
                messagebox.showerror(
                    "Teyit",
                    "Teyit kaydedilemedi (log'a bakın).",
                    parent=getattr(self, '_sema_tam_top', None) or self.root,
                )
            except Exception:
                pass
            return
        self._state_kaydet()
        # Header'daki teyit etiketini güncelle
        self._sema_teyit_lbl_guncelle(satir)

    def _aktif_kullanici_adi(self) -> str:
        """Teyit kaydında saklanacak kullanıcı adı. Windows oturum kullanıcısı."""
        try:
            return os.getlogin()
        except Exception:
            return ""

    def _ana_teyit_kaydet(self, teyit_sonucu: str) -> None:
        """Ana ekran toolbar'ındaki teyit butonları — seçili satırların REÇETESİNE uygula.

        Hedef belirleme önceliği:
            1) Treeview multi-selection (Ctrl+Click ile seçilenler)
            2) ☑ ile işaretli satırlar (self.secili_iidler) — boşsa
            3) Hiçbiri yoksa uyarı.

        Seçilen her satır için aynı reçeteye ait tüm ilaç satırları
        teyit edilir ve teyit sonucuna karşılık gelen renge boyanır
        (UYGUN=yeşil, ŞÜPHELİ=sarı, UYGUN DEĞİL=kırmızı). Çoklu reçete
        (>=2) için onay diyaloğu. Üzerine yazar (son teyit geçerli).
        """
        # 1) Hedef ri_idleri belirle
        try:
            sec = list(self.tv.selection())
        except Exception:
            sec = []
        hedef_iidler = sec or list(getattr(self, "secili_iidler", set()) or [])
        if not hedef_iidler:
            try:
                messagebox.showwarning(
                    "Manuel Teyit",
                    "Önce tablodan bir veya daha fazla reçete seçin "
                    "(Ctrl+Click veya ☑ kutucuğu).",
                    parent=self.root,
                )
            except Exception:
                pass
            return

        # Reçete bazlı genişlet: her hedef iid'in reçetesindeki tüm satırlar dahil
        genis_iidler: set = set()
        recete_sayisi: set = set()
        for iid in hedef_iidler:
            grup = self._recetenin_tum_iidleri(iid)
            genis_iidler.update(grup)
            satir = self.satir_indeks.get(iid)
            if satir:
                anahtar = (str(satir.get("rec_no") or "").strip()
                           or str(satir.get("sistem_recete_no") or "").strip()
                           or iid)
                recete_sayisi.add(anahtar)
        hedef_iidler = list(genis_iidler)

        etiket = recete_teyit_db.ETIKET.get(teyit_sonucu, teyit_sonucu)
        if len(recete_sayisi) >= 2:
            if not messagebox.askyesno(
                "Manuel Teyit",
                f"{len(recete_sayisi)} reçete ({len(hedef_iidler)} ilaç satırı) "
                f"'{etiket}' olarak teyit edilecek. Devam edilsin mi?\n\n"
                f"(Mevcut teyitlerin üzerine yazılır.)",
                parent=self.root,
            ):
                return

        # 2) Cache'i hazırla
        if not hasattr(self, "_teyit_map") or self._teyit_map is None:
            self._teyit_map = {}
        kullanici = self._aktif_kullanici_adi()
        yeni_renk = TEYIT_RENK.get(teyit_sonucu, RENK_BEYAZ)

        # 3) Her hedef için DB'ye yaz + tabloyu update et + rengi uygula
        basarili = 0
        basarisiz = 0
        for iid in hedef_iidler:
            satir = self.satir_indeks.get(iid)
            if not satir:
                basarisiz += 1
                continue
            ok = recete_teyit_db.teyit_kaydet(
                iid,
                teyit_sonucu,
                hasta_tc=str(satir.get("tc") or ""),
                recete_no=str(satir.get("rec_no") or ""),
                ilac_adi=str(satir.get("ilac") or ""),
                sut_kategorisi=str(satir.get("sut") or ""),
                kullanici=kullanici,
                otomatik_sonuc=str(satir.get("verdict") or ""),
            )
            if not ok:
                basarisiz += 1
                continue
            self._teyit_map[iid] = teyit_sonucu
            satir["teyit"] = recete_teyit_db.rozet(teyit_sonucu)
            self.satir_renkleri[iid] = yeni_renk
            try:
                values = tuple(str(satir.get(k, "")) for k in SUTUN_KOD)
                self.tv.item(iid, values=values,
                             tags=(yeni_renk, "teyit_bold"))
            except Exception:
                pass
            basarili += 1

        # 4) Renk state'ini kalıcı kaydet
        self._state_kaydet()

        # 5) Tam ekran şema açıksa header teyit etiketi de güncellensin
        try:
            sema_satir = self._aktif_satir()
            if sema_satir:
                self._sema_teyit_lbl_guncelle(sema_satir)
        except Exception:
            pass

        # 6) Durum mesajı
        mesaj = (f"Teyit: {len(recete_sayisi)} reçete / {basarili} satır "
                 f"{etiket}")
        if basarisiz:
            mesaj += f"  ({basarisiz} başarısız)"
        try:
            self._durum_yaz(mesaj)
        except Exception:
            pass

    def _ana_teyit_kaldir(self) -> None:
        """Sağ tık menüsünden çağrılır — seçili satırların REÇETELERİNİN teyitini sil.

        Aynı reçeteye ait tüm ilaç satırlarının rozeti, bold tag'i ve arka
        plan rengi (manuel teyit ile boyanan) temizlenir; DB'den kayıt silinir.
        """
        try:
            sec = list(self.tv.selection())
        except Exception:
            sec = []
        hedef_iidler = sec or list(getattr(self, "secili_iidler", set()) or [])
        if not hedef_iidler:
            return

        # Reçete bazlı genişlet
        genis_iidler: set = set()
        recete_sayisi: set = set()
        for iid in hedef_iidler:
            genis_iidler.update(self._recetenin_tum_iidleri(iid))
            satir = self.satir_indeks.get(iid)
            if satir:
                anahtar = (str(satir.get("rec_no") or "").strip()
                           or str(satir.get("sistem_recete_no") or "").strip()
                           or iid)
                recete_sayisi.add(anahtar)
        hedef_iidler = list(genis_iidler)

        if len(recete_sayisi) >= 2:
            if not messagebox.askyesno(
                "Teyit Kaldır",
                f"{len(recete_sayisi)} reçete ({len(hedef_iidler)} ilaç satırı) "
                f"teyiti silinecek. Devam edilsin mi?",
                parent=self.root,
            ):
                return

        if not hasattr(self, "_teyit_map") or self._teyit_map is None:
            self._teyit_map = {}

        silinen = 0
        for iid in hedef_iidler:
            satir = self.satir_indeks.get(iid)
            if not satir:
                continue
            recete_teyit_db.teyit_sil(iid)
            self._teyit_map.pop(iid, None)
            satir["teyit"] = ""
            # Manuel teyit ile boyanan rengi sıfırla (yeşil/sarı/kırmızı → beyaz)
            self.satir_renkleri[iid] = RENK_BEYAZ
            try:
                values = tuple(str(satir.get(k, "")) for k in SUTUN_KOD)
                self.tv.item(iid, values=values, tags=(RENK_BEYAZ,))
            except Exception:
                pass
            silinen += 1

        # Renk state'ini kalıcı kaydet
        self._state_kaydet()

        try:
            sema_satir = self._aktif_satir()
            if sema_satir:
                self._sema_teyit_lbl_guncelle(sema_satir)
        except Exception:
            pass

        try:
            self._durum_yaz(f"Teyit kaldırıldı: {silinen} satır")
        except Exception:
            pass

    def _ana_teyit_kaldir_tumu(self) -> None:
        """Tüm görünen (filtrelenmiş) satırların teyitlerini sıfırlar.
        Kullanıcı isteği 2026-05-17 — toplu teyit temizleme butonu.

        Sadece TreeView'de gösterilen satırları etkiler (filtre dışı satırlar
        dokunulmaz). Aktif teyiti olmayan satırlar atlanır.
        """
        # Görünen satırlar (filtreden geçenler)
        try:
            gorunen_iidler = list(self.tv.get_children())
        except Exception:
            gorunen_iidler = []
        if not gorunen_iidler:
            try:
                messagebox.showinfo(
                    "Teyit Kaldır",
                    "Görünen reçete satırı yok.",
                    parent=self.root)
            except Exception:
                pass
            return

        # Aktif teyiti olanları topla
        if not hasattr(self, "_teyit_map") or self._teyit_map is None:
            self._teyit_map = {}
        teyitli_iidler = [iid for iid in gorunen_iidler
                           if self._teyit_map.get(iid)
                           or (self.satir_indeks.get(iid) or {}).get("teyit")]
        recete_sayisi = set()
        for iid in teyitli_iidler:
            s = self.satir_indeks.get(iid)
            if s:
                recete_sayisi.add(
                    str(s.get("rec_no") or "").strip()
                    or str(s.get("sistem_recete_no") or "").strip()
                    or iid)
        if not teyitli_iidler:
            try:
                messagebox.showinfo(
                    "Teyit Kaldır",
                    "Görünen satırlarda teyitli kayıt yok.",
                    parent=self.root)
            except Exception:
                pass
            return

        # Onay
        if not messagebox.askyesno(
            "Teyit Kaldır — Tümü",
            f"Görünen {len(recete_sayisi)} reçete ({len(teyitli_iidler)} "
            f"ilaç satırı) teyiti silinecek.\n\nDevam edilsin mi?",
            parent=self.root,
        ):
            return

        silinen = 0
        for iid in teyitli_iidler:
            satir = self.satir_indeks.get(iid)
            if not satir:
                continue
            try:
                recete_teyit_db.teyit_sil(iid)
            except Exception:
                pass
            self._teyit_map.pop(iid, None)
            satir["teyit"] = ""
            self.satir_renkleri[iid] = RENK_BEYAZ
            try:
                values = tuple(str(satir.get(k, "")) for k in SUTUN_KOD)
                self.tv.item(iid, values=values, tags=(RENK_BEYAZ,))
            except Exception:
                pass
            silinen += 1

        self._state_kaydet()

        try:
            sema_satir = self._aktif_satir()
            if sema_satir:
                self._sema_teyit_lbl_guncelle(sema_satir)
        except Exception:
            pass

        try:
            self._durum_yaz(
                f"Toplu teyit kaldırıldı: {silinen} satır "
                f"({len(recete_sayisi)} reçete)")
        except Exception:
            pass

    def _sema_temizle(self, mesaj: str = "") -> None:
        """Şema panelini temizle, opsiyonel placeholder mesaj.

        Aktif sekmeler: Tab D (DMN) + Tab G (Klasik Akım).
        Tab A/B/C/E/F kaldırıldığı için ilgili canvas'lar yoktur;
        hasattr ile kontrol edilir.
        """
        for w in self._sema_ozet.winfo_children():
            w.destroy()
        # Aktif canvas'ları temizle (D + G)
        if hasattr(self, '_dmn_canvas'):
            try:
                self._dmn_canvas.delete("all")
                self._dmn_neden_map = {}
            except Exception:
                pass
        if hasattr(self, '_klasik_canvas'):
            try:
                self._klasik_canvas.delete("all")
                self._klasik_neden_map = {}
            except Exception:
                pass
        if mesaj:
            tk.Label(self._sema_ozet, text=mesaj, bg="#FAFBFC",
                     fg="#90A4AE",
                     font=("Segoe UI", 9, "italic")).pack(pady=20)

    def _dmn_canvas_hover(self, event) -> None:
        """DMN Karar Modeli canvas hover — hücre/atom için neden tooltip."""
        try:
            c = self._dmn_canvas
            cx = c.canvasx(event.x)
            cy = c.canvasy(event.y)
            items = c.find_overlapping(cx - 1, cy - 1, cx + 1, cy + 1)
            for it in items:
                if it in self._dmn_neden_map:
                    if getattr(self, "_sema_tip_item", None) == it:
                        return
                    self._sema_hide_tip()
                    neden = self._dmn_neden_map[it]
                    x = c.winfo_rootx() + event.x + 16
                    y = c.winfo_rooty() + event.y + 16
                    tip = tk.Toplevel(self.root)
                    tip.wm_overrideredirect(True)
                    tip.wm_geometry(f"+{x}+{y}")
                    tk.Label(tip, text=neden, bg="#FFFDE7", fg="#37474F",
                             font=("Segoe UI", 9), justify="left",
                             relief="solid", bd=1, padx=6, pady=3,
                             wraplength=420).pack()
                    self._sema_tip = tip
                    self._sema_tip_item = it
                    return
            self._sema_hide_tip()
        except Exception:
            pass

    def _klasik_canvas_hover(self, event) -> None:
        """Klasik Akım Şeması canvas hover — ampul için neden tooltip."""
        try:
            c = self._klasik_canvas
            cx = c.canvasx(event.x)
            cy = c.canvasy(event.y)
            items = c.find_overlapping(cx - 1, cy - 1, cx + 1, cy + 1)
            for it in items:
                if it in self._klasik_neden_map:
                    if getattr(self, "_sema_tip_item", None) == it:
                        return
                    self._sema_hide_tip()
                    neden = self._klasik_neden_map[it]
                    x = c.winfo_rootx() + event.x + 16
                    y = c.winfo_rooty() + event.y + 16
                    tip = tk.Toplevel(self.root)
                    tip.wm_overrideredirect(True)
                    tip.wm_geometry(f"+{x}+{y}")
                    tk.Label(tip, text=neden, bg="#FFFDE7", fg="#37474F",
                             font=("Segoe UI", 9), justify="left",
                             relief="solid", bd=1, padx=6, pady=3,
                             wraplength=420).pack()
                    self._sema_tip = tip
                    self._sema_tip_item = it
                    return
            self._sema_hide_tip()
        except Exception:
            pass

    def _sema_secim_guncelle(self, _event=None) -> None:
        """Treeview'de seçilen reçete için şema panelini günceller."""
        try:
            secimler = self.tv.selection()
            if not secimler:
                self._sema_temizle("Bir reçete satırı seçin")
                # Tam ekran nav/teyit etiketlerini de temizle
                self._sema_nav_lbl_guncelle()
                self._sema_teyit_lbl_guncelle(None)
                return
            iid = secimler[0]  # ilk seçili — iid = str(s["ri_id"])
            # tum_satirlar içinde ri_id eşleşmesi
            satir = None
            for s in (self.tum_satirlar or []):
                if str(s.get("ri_id")) == str(iid):
                    satir = s
                    break
            if satir is None:
                self._sema_temizle("Satır bulunamadı")
                self._sema_nav_lbl_guncelle()
                self._sema_teyit_lbl_guncelle(None)
                return
            self._sema_render(satir)
            # Tam ekran açıksa nav sayaç + teyit etiket güncelle
            self._sema_nav_lbl_guncelle()
            self._sema_teyit_lbl_guncelle(satir)
            # Tam ekran açıksa hasta/reçete bilgi şeridini ve pencere
            # başlığını güncelle (kullanıcı tam ekranda kimi kontrol
            # ettiğini her zaman görsün)
            self._sema_tam_bilgi_guncelle(satir)
            # Diğer yolaklar paneli (toggle açıksa veya kapalıyken bile veri
            # ön belleğe alınır — açılırsa liste hazır olsun)
            self._diger_yolaklar_doldur(satir)
        except Exception as e:
            self._sema_temizle(f"Hata: {e}")

    # ─────────────────────────────────────────────────────────────────
    # DİĞER YOLAKLAR PANELİ — dispatcher'ın elediği yolakları göster
    # ─────────────────────────────────────────────────────────────────
    def _diger_yolaklar_toggle(self) -> None:
        """🔍 toggle: alt paneli pack/forget."""
        if getattr(self, '_diger_yolak_panel_acik', False):
            try:
                self._diger_yolak_frame.pack_forget()
            except Exception:
                pass
            self._diger_yolak_panel_acik = False
            try:
                self._diger_yolak_btn.configure(fg="#FFCC80")
            except Exception:
                pass
        else:
            try:
                self._diger_yolak_frame.pack(side="bottom", fill="x",
                                              padx=4, pady=(4, 4))
            except Exception:
                pass
            self._diger_yolak_panel_acik = True
            try:
                self._diger_yolak_btn.configure(fg="#FFEB3B")
            except Exception:
                pass

    def _diger_yolaklar_doldur(self, satir: Optional[Dict]) -> None:
        """Aktif satırın `verdict_detaylar` JSON'undan diger_yolaklar listesini
        çıkar ve Listbox'ı doldur. Hepatit dışı kontroller için liste boş —
        panel 'desteklenmiyor' mesajı gösterir."""
        self._diger_yolak_aktif_satir = satir
        self._diger_yolak_aktif_liste = []
        lb = getattr(self, '_diger_yolak_listbox', None)
        tx = getattr(self, '_diger_yolak_text', None)
        if not lb or not tx:
            return
        try:
            lb.delete(0, tk.END)
            tx.configure(state="normal")
            tx.delete("1.0", tk.END)
        except Exception:
            return

        if not satir:
            tx.insert("1.0", "(Reçete seçili değil)")
            tx.configure(state="disabled")
            return

        # verdict_detaylar JSON'ında diger_yolaklar var mı?
        det_json = satir.get("verdict_detaylar") or ""
        diger = []
        aktif_meta = None
        try:
            if det_json:
                det = json.loads(det_json) if isinstance(det_json, str) else det_json
                diger = det.get("diger_yolaklar") or []
                aktif_meta = det.get("aktif_yolak_meta")
        except Exception:
            diger = []

        if not diger:
            tx.insert("1.0",
                       "Bu kontrol modülü 'diğer yolaklar' API'sini henüz "
                       "desteklemiyor. Şimdilik sadece hepatit (HBV/HCV/HDV) "
                       "kontrollerinde aktif.\n\n"
                       "Hepatit reçetesi seçerseniz dispatcher'ın elediği "
                       "11 pasif yolak burada listelenir.")
            tx.configure(state="disabled")
            return

        self._diger_yolak_aktif_liste = diger
        # Başlık satırı (aktif yolak)
        if aktif_meta:
            tx.insert(
                "1.0",
                f"✅ AKTİF YOLAK: {aktif_meta.get('ad','?')} "
                f"(SUT {aktif_meta.get('sut','?')})\n\n"
                "Sol listede pasif yolak başlıklarına tıklayınca "
                "o yolağın atomik şartları LAZY hesaplanır ve burada "
                "görüntülenir.")
        else:
            tx.insert("1.0", "Sol listeden bir pasif yolak seçin.")
        tx.configure(state="disabled")

        # Listbox'ı doldur
        for d in diger:
            ad = d.get("ad") or d.get("kod") or "?"
            sut = d.get("sut") or "?"
            sebep = d.get("eleme_nedeni") or ""
            satir_metin = f"{d.get('kod','?')} {ad} (SUT {sut})"
            if sebep:
                satir_metin += f"  ⟵ {sebep[:70]}"
            lb.insert(tk.END, satir_metin)

    def _diger_yolaklar_secim(self, _event=None) -> None:
        """Listbox'tan seçim → lazy yolak hesapla → atomları metin olarak göster."""
        lb = getattr(self, '_diger_yolak_listbox', None)
        tx = getattr(self, '_diger_yolak_text', None)
        if not lb or not tx:
            return
        sel = lb.curselection()
        if not sel:
            return
        idx = sel[0]
        if idx >= len(self._diger_yolak_aktif_liste):
            return
        secilen = self._diger_yolak_aktif_liste[idx]
        kod = secilen.get("kod")
        ad = secilen.get("ad") or kod
        satir = self._diger_yolak_aktif_satir
        if not satir or not kod:
            return

        tx.configure(state="normal")
        tx.delete("1.0", tk.END)
        tx.insert("1.0",
                   f"⏳ {kod} {ad} — atomlar hesaplanıyor (lazy)...\n")
        tx.configure(state="disabled")
        tx.update_idletasks()

        # Hepatit için lazy hesap
        try:
            from recete_kontrol.hepatit_kontrol import hepatit_yolak_hesapla
            ilac_sonuc = self._ilac_sonuc_olustur_hepatit(satir)
            rapor = hepatit_yolak_hesapla(ilac_sonuc, kod)
        except Exception as e:
            tx.configure(state="normal")
            tx.delete("1.0", tk.END)
            tx.insert("1.0", f"❌ Hesap hatası: {e}")
            tx.configure(state="disabled")
            return

        # Sonucu metin olarak ekrana yaz
        tx.configure(state="normal")
        tx.delete("1.0", tk.END)
        tx.insert(tk.END, f"📋 {kod} — {ad}\n")
        tx.insert(tk.END, f"   Eleme nedeni: {secilen.get('eleme_nedeni','—')}\n\n")
        tx.insert(tk.END, f"➡ HESAPLANAN SONUÇ: {rapor.sonuc.value.upper()}\n")
        if rapor.mesaj:
            tx.insert(tk.END, f"   {rapor.mesaj}\n")
        tx.insert(tk.END, "\n── ATOMİK ŞARTLAR ─────────────────\n")
        gruplar_dict: Dict[str, List] = {}
        for s in (rapor.sartlar or []):
            g = getattr(s, 'grup', '') or '(grupsuz)'
            gruplar_dict.setdefault(g, []).append(s)
        for grup_ad, atomlar in gruplar_dict.items():
            tx.insert(tk.END, f"\n● {grup_ad}\n")
            for a in atomlar:
                dur = a.durum.value if hasattr(a.durum, 'value') else str(a.durum)
                sym = {'var': '✓', 'yok': '✗',
                        'kontrol_edilemedi': '?'}.get(dur, '·')
                tx.insert(tk.END, f"   {sym} {a.ad}\n")
                if a.neden:
                    tx.insert(tk.END, f"      └─ {a.neden}\n")
        tx.configure(state="disabled")

    def _sema_heyet_brans_listesi(self, rapor_ana_id) -> list:
        """Verilen RaporAnaId için heyet doktorlarının branş listesi.
        Cache'li (rapor_ana_id → ['Kardiyoloji', 'Genel Cerrahi', ...]).
        Boş list = RaporDoktor satırı yok ya da branş bilgisi eksik."""
        if not rapor_ana_id:
            return []
        cache = getattr(self, '_sema_heyet_brans_cache', None)
        if cache is None:
            cache = {}
            self._sema_heyet_brans_cache = cache
        if rapor_ana_id in cache:
            return cache[rapor_ana_id]
        try:
            rows = self.db.sorgu_calistir(
                """SELECT b.BransAdi
                   FROM RaporDoktor rd
                   LEFT JOIN Brans b ON b.BransId = rd.RaporDoktorBransId
                   WHERE rd.RaporDoktorRaporAnaId = ?
                     AND (rd.RaporDoktorSilme IS NULL
                          OR rd.RaporDoktorSilme = 0)
                   ORDER BY b.BransAdi""",
                (rapor_ana_id,))
            branslar = [(r.get('BransAdi') or '').strip()
                         for r in rows if (r.get('BransAdi') or '').strip()]
        except Exception:
            branslar = []
        cache[rapor_ana_id] = branslar
        return branslar

    def _sema_tam_bilgi_guncelle(self, satir: dict) -> None:
        """Tam ekran şema penceresinde info_bar + window title'ı güncelle."""
        top = getattr(self, '_sema_tam_top', None)
        if not top:
            return
        try:
            hasta = (satir.get("hasta") or "—").strip()
            tc = (satir.get("tc") or "").strip()
            rec_tar = (satir.get("rec_tar") or "").strip()
            rec_no = (satir.get("rec_no") or "").strip()
            sis_no = (satir.get("sistem_recete_no") or "").strip()
            ilac = (satir.get("ilac") or "").strip()
            verdict = (satir.get("verdict") or "").strip()
            rec_brans = (satir.get("brans") or "").strip()
            rec_tesh = (satir.get("rec_tesh") or "").strip()
            rec_ack = (satir.get("rec_ack") or "").strip()
            rap_kod = (satir.get("rap_kod") or "").strip()
            rap_kod_ack = (satir.get("rap_kod_aciklama") or "").strip()
            rap_tak_no = (satir.get("rap_tak_no") or "").strip()
            rap_brans = (satir.get("rapor_doktor_brans") or "").strip()
            rap_tesh = (satir.get("rap_tesh") or "").strip()
            rap_ack = (satir.get("rap_ack") or "").strip()

            def _kirp(s: str, n: int) -> str:
                """Tek satıra düzleştir + uzunsa kırp (label görünür kısmı için)."""
                if not s:
                    return ""
                t = " ".join(s.split())
                return t if len(t) <= n else t[: n - 1] + "…"

            def _duz(s: str) -> str:
                """Tek satıra düzleştir, kırpma YOK (tooltip için tam metin)."""
                return " ".join(s.split()) if s else ""

            # ── SOL — REÇETE (2 satır, yataya yayılmış) ─────────────────
            # Satır 1: hasta · TC · reç.tar · e-reç · sis.reç · ilaç
            sol_s1 = [hasta]
            if tc:
                sol_s1.append(f"TC {tc}")
            if rec_tar:
                sol_s1.append(f"Reç.Tar {rec_tar}")
            if rec_no:
                sol_s1.append(f"E-Reç {rec_no}")
            if sis_no and sis_no != rec_no:
                sol_s1.append(f"Sis.Reç {sis_no}")
            if ilac:
                sol_s1.append(f"İlaç: {ilac}")
            # Satır 2: reç. yazan dr branşı · reç. teşhisi · reç. açıklaması · → SONUÇ
            # Cap büyük tutuldu (200/300) — wraplength alt satıra geçirir; kalan
            # uzun metin tooltip'te tam okunur.
            sol_s2 = [f"Reç.Yazan: {rec_brans or '?'}"]
            if rec_tesh:
                sol_s2.append(f"Reç.Teşhisi: {_kirp(rec_tesh, 200)}")
            if rec_ack:
                sol_s2.append(f"Reç.Açıklaması: {_kirp(rec_ack, 300)}")
            if verdict:
                sol_s2.append(f"→ {verdict}")
            sol_metin = "  ·  ".join(sol_s1) + "\n" + "  ·  ".join(sol_s2)

            # Tooltip için TAM (kırpılmamış) metin
            sol_tt_lines = [
                "═══ REÇETE ═══",
                "  ·  ".join(sol_s1),
                f"Reç.Yazan: {rec_brans or '?'}",
            ]
            if rec_tesh:
                sol_tt_lines.append(f"Reç.Teşhisi: {_duz(rec_tesh)}")
            if rec_ack:
                sol_tt_lines.append(f"Reç.Açıklaması: {_duz(rec_ack)}")
            if verdict:
                sol_tt_lines.append(f"Genel sonuç: {verdict}")
            sol_tt = "\n".join(sol_tt_lines)

            # ── SAĞ — RAPOR (2 satır, yataya yayılmış) ──────────────────
            if rap_kod:
                # Heyet branş listesi (3 doktor varsa: "Kard · Gen.Cer · Nöro")
                rapor_ana_id = satir.get("rapor_ana_id")
                heyet_branslar = self._sema_heyet_brans_listesi(rapor_ana_id)
                if heyet_branslar:
                    yazan_str = " · ".join(heyet_branslar)
                elif rap_brans:
                    yazan_str = rap_brans  # fallback — tek branş
                else:
                    secim_kaynagi = (
                        satir.get("rapor_secim_kaynagi") or "").lower()
                    if not rapor_ana_id or "sr_no_rapana" in secim_kaynagi:
                        yazan_str = "(rapor DB'de yok)"
                    else:
                        yazan_str = "(heyet DB'de yok)"

                # Satır 1: rapor kodu + kod metni · rapor no · rapor ICD teşhisleri · raporu yazan branşları
                kod_seg = rap_kod
                if rap_kod_ack:
                    kod_seg += f" — {_kirp(rap_kod_ack, 80)}"
                sag_s1 = [f"Rapor: {kod_seg}"]
                if rap_tak_no:
                    sag_s1.append(f"No {rap_tak_no}")
                if rap_tesh:
                    sag_s1.append(f"Teşhis: {_kirp(rap_tesh, 120)}")
                sag_s1.append(f"Yazan: {yazan_str}")
                # Satır 2: rapor açıklaması (geniş alan — yataya yayılır)
                sag_s2 = (f"Rapor Açıklaması: {_kirp(rap_ack, 400)}"
                           if rap_ack else "Rapor Açıklaması: —")
                sag_metin = "  ·  ".join(sag_s1) + "\n" + sag_s2

                # Tooltip için TAM metin
                sag_tt_lines = ["═══ RAPOR ═══",
                                  f"Rapor Kodu: {rap_kod}"
                                  + (f" — {_duz(rap_kod_ack)}" if rap_kod_ack
                                     else "")]
                if rap_tak_no:
                    sag_tt_lines.append(f"Rapor No: {rap_tak_no}")
                if rap_tesh:
                    sag_tt_lines.append(f"Rapor Teşhisi: {_duz(rap_tesh)}")
                sag_tt_lines.append(f"Rapor Yazan: {yazan_str}")
                if rap_ack:
                    sag_tt_lines.append(f"Rapor Açıklaması: {_duz(rap_ack)}")
                sag_tt = "\n".join(sag_tt_lines)
            else:
                sag_metin = "Rapor: yok (raporsuz reçete)\n"
                sag_tt = "═══ RAPOR ═══\nRaporsuz reçete"

            rec_lbl = getattr(self, '_sema_tam_info_rec_lbl', None)
            if rec_lbl is not None:
                rec_lbl.config(text=sol_metin)
            rap_lbl = getattr(self, '_sema_tam_info_rap_lbl', None)
            if rap_lbl is not None:
                rap_lbl.config(text=sag_metin)
            # Tooltip metinlerini güncelle (hover'da tam metin görünür)
            tt_rec = getattr(self, '_sema_tam_tt_rec', None)
            if tt_rec is not None:
                tt_rec.text = sol_tt
            tt_rap = getattr(self, '_sema_tam_tt_rap', None)
            if tt_rap is not None:
                tt_rap.text = sag_tt

            # Pencere title (taskbar'da da görünür)
            title_kisa = f"📋 {hasta}"
            if rec_no:
                title_kisa += f" — {rec_no}"
            if rec_tar:
                title_kisa += f" ({rec_tar})"
            title_kisa += "  —  Atomik SUT Devre Şeması (ESC kapat)"
            top.title(title_kisa)
        except Exception:
            pass

    @staticmethod
    def _sema_grup_matematigi(sartlar: list) -> dict:
        """VEYA-aware şart matematiği — kaç gerekli, kaç sağlanıyor.

        Kurallar:
          • "(bilgi)" suffix grup → tamamen hesap dışı
          • veya_grubu=True olan grup (≥1 yeterli):
              gerekli = 1
              sağlanan = min(1, VAR sayısı)
          • Diğer (AND) gruplar:
              gerekli = grup uzunluğu
              sağlanan = VAR sayısı
          • Üst-VEYA çiftleri ("(a)" VEYA "(b)"; "Varfarin (D-2)" VEYA
            "İstisna grubu (D-2)"):
              en az birinin saglanan==gerekli olduğu yol seçilir;
              ikisi de tam değilse → daha tam olan seçilir; eşitse minimum
              gerekli olan yol baz alınır.

        Returns: {
            'gerekli_toplam': int,
            'saglanan_toplam': int,
            'gruplar': [{'grup', 'gerekli', 'saglanan', 'toplam',
                         'veya', 'durum_kismi'}],
        }
        """
        # Gruplara ayır (sıra korunur)
        gruplar_dict: dict = {}
        sira = []
        for s in sartlar:
            g = s.get("grup", "") or "(grupsuz)"
            if g not in gruplar_dict:
                gruplar_dict[g] = []
                sira.append(g)
            gruplar_dict[g].append(s)

        # İlk pass — her grubun gerekli/saglanan'ını hesapla
        ham_gruplar = {}
        for g in sira:
            # (bilgi) ve [pasif] gruplar hesap dışı
            if "(bilgi)" in g or "[pasif]" in g:
                continue
            gs = gruplar_dict[g]
            veya = any(s.get("veya_grubu") for s in gs)
            var_sayi = sum(1 for s in gs if s.get("durum") == "var")
            toplam_sayi = len(gs)
            if veya:
                gerekli, saglanan = 1, min(1, var_sayi)
            else:
                gerekli, saglanan = toplam_sayi, var_sayi
            ham_gruplar[g] = {
                "grup": g, "gerekli": gerekli, "saglanan": saglanan,
                "toplam": toplam_sayi, "veya": veya,
                "var_sayi": var_sayi,
            }

        # Üst-VEYA çiftleri — birleştir
        cift_prefix_listesi = [
            ("Varfarin yolu (a)", "Varfarin yolu (b)",
             "Varfarin yolu [(a) VEYA (b)]"),
            ("Varfarin yolu (D-2", "İstisna grubu (D-2",
             "Varfarin VEYA istisna [(1)(b) VEYA (2)]"),
            # Fibrat SUT 4.2.28.B: Yol-a (TG>500) ∨ Yol-b (TG>200 + ≥1 KV)
            ("Yol-a — TG>500", "Yol-b — TG>200",
             "Fibrat başlama [(a) VEYA (b)]"),
            # Klopidogrel SUT 4.2.15.A(2) Y-2 alt-yol:
            #   Yol-A: raporsuz akut akış (reçete yazan yetkili)
            #   Yol-B: raporlu 12 ay (rapor mevcut ∧ rapor yazan yetkili AND)
            ("Y-2: (a) Raporsuz akış", "Y-2: (b) Raporlu 12 ay",
             "Y-2: Yetkili akış [(a) VEYA (b)]"),
        ]
        for pa, pb, birlesik in cift_prefix_listesi:
            ka = next((k for k in ham_gruplar if k.startswith(pa)), None)
            kb = next((k for k in ham_gruplar if k.startswith(pb)), None)
            if ka and kb:
                ga, gb = ham_gruplar[ka], ham_gruplar[kb]
                # En kısa yol = düşük gerekli; tamamlanmış olan tercih
                a_tam = ga["saglanan"] == ga["gerekli"]
                b_tam = gb["saglanan"] == gb["gerekli"]
                if a_tam and not b_tam:
                    secilen = ga
                elif b_tam and not a_tam:
                    secilen = gb
                elif a_tam and b_tam:
                    # ikisi de tam → daha kısa olanı seç
                    secilen = ga if ga["gerekli"] <= gb["gerekli"] else gb
                else:
                    # ikisi de eksik → daha çok ilerlemiş veya minimum gerekli
                    if ga["saglanan"] > gb["saglanan"]:
                        secilen = ga
                    elif gb["saglanan"] > ga["saglanan"]:
                        secilen = gb
                    else:
                        # eşit → minimum gerekli
                        secilen = ga if ga["gerekli"] <= gb["gerekli"] else gb
                ham_gruplar[birlesik] = {
                    "grup": birlesik,
                    "gerekli": secilen["gerekli"],
                    "saglanan": secilen["saglanan"],
                    "toplam": ga["toplam"] + gb["toplam"],
                    "veya": True,
                    "var_sayi": ga["var_sayi"] + gb["var_sayi"],
                    "secilen_yol": secilen["grup"],
                }
                # Alt grupları sil yerine "alt" işaretle: detail render
                # (üst-VEYA paralel blok) saglanan/gerekli erişimini korur,
                # totals'da çift sayılmasın diye `alt` filtrelenir.
                ham_gruplar[ka]["alt"] = True
                ham_gruplar[kb]["alt"] = True

        # Üst-VEYA çoklu (n-way): D-1(1) risk faktörü 4 alt-grup → tek üst-OR
        # SUT lafzı (a)∨(b)∨(c)∨(d): ≥1 yeterli; alt-gruplar görsel kalır,
        # toplamlarda alt=True ile dışlanır.
        coklu_prefix_listesi = [
            (("Risk fakt. (a) — inme/TIA",
              "Risk fakt. (b) — ≥75 yaş",
              "Risk fakt. (c) — NYHA",
              "Risk fakt. (d) — DM/HT"),
             "Risk faktörü ≥1 [(a)∨(b)∨(c)∨(d)]"),
            # Statin SUT 4.2.28.A: 5 başlama yolu + idame n-way üst-OR
            (("Yol-a — LDL>190",
              "Yol-b — LDL>160",
              "Yol-c — LDL>130",
              "Yol-ç(1) — LDL>100",
              "Yol-ç(2) — LDL>70",
              "Yol-İdame —"),
             "Statin başlama [(a)∨(b)∨(c)∨(ç₁)∨(ç₂)∨İdame]"),
        ]
        for prefixes, birlesik in coklu_prefix_listesi:
            keys = [next((k for k in ham_gruplar if k.startswith(p)), None)
                    for p in prefixes]
            keys = [k for k in keys if k]
            if not keys:
                continue
            gruplari = [ham_gruplar[k] for k in keys]
            # Tam olanlardan ilki "seçilen"; yoksa max saglanan; yoksa ilk
            tam_olanlar = [g for g in gruplari
                           if g["saglanan"] >= g["gerekli"]
                           and g["gerekli"] > 0]
            if tam_olanlar:
                secilen = min(tam_olanlar, key=lambda g: g["gerekli"])
            else:
                secilen = max(gruplari, key=lambda g: g["saglanan"])
            ham_gruplar[birlesik] = {
                "grup": birlesik,
                "gerekli": 1,
                "saglanan": 1 if tam_olanlar else 0,
                "toplam": sum(g["toplam"] for g in gruplari),
                "veya": True,
                "var_sayi": sum(g["var_sayi"] for g in gruplari),
                "secilen_yol": secilen["grup"],
            }
            for k in keys:
                ham_gruplar[k]["alt"] = True

        # ─── GENERIC ÇOKLU-YOLAK ÜST-VEYA ────────────────────────────────
        # Herhangi bir SUT kontrolü atomik şartlarını "[YPT]-<n>: ..."
        # prefix'iyle yazmışsa, sema panel otomatik paralel şema (üst-OR)
        # çıkarır:
        #   Y-<n> → Klopidogrel SUT 4.2.15.A (4 yolak)
        #   P-<n> → Prasugrel SUT 4.2.15.Ç (2 yolak: P-1 ∨ P-2)
        #   T-<n> → Tikagrelor SUT 4.2.15.E (tek yolak — şema tek kol gösterir)
        # NOT: "P-Yol-A/B" ve "T-Yol-A/B" akış grupları, yolak değil; bu
        # regex '[YPT]-<rakam>:' deseni nedeniyle bunları yakalamaz (Yol-A'da
        # tire sonrası harf var, rakam değil).
        # Adımlar:
        #   1) sartlar'daki tüm "[YPT]-<n>:" grupları regex ile tespit.
        #   2) Her yolak içi gruplar AND'lenir → sanal yolak.
        #   3) Tüm yolaklar arası ≥1 yeterli (üst-OR).
        # Grup adı sonu: tek harf (P-1A:, P-2B:) veya direkt ':'.
        # Regex grup(1)="Y-1"/"P-1"/"T-1", grup(2)="1".
        import re as _re
        _yolak_pat = _re.compile(r'^([YPT]-(\d+))[A-Z]?:')
        _yolak_no_keys: dict = {}  # {"Y-1": [...], "P-1": [...], "T-1": [...]}
        for k in list(ham_gruplar.keys()):
            if ham_gruplar[k].get("alt") or ham_gruplar[k].get("sanal_yolak"):
                continue
            m = _yolak_pat.match(k)
            if m:
                yol_prefix = m.group(1)  # "Y-1" / "P-1" / "T-1"
                _yolak_no_keys.setdefault(yol_prefix, []).append(k)
        yolak_sanal_keys = []
        # Yolaklar sırasında işlenir (Y/P/T harfi + numara)
        for yol_prefix in sorted(_yolak_no_keys.keys(),
                                  key=lambda p: (p[0], int(p.split('-')[1]))):
            yolak_keys = _yolak_no_keys[yol_prefix]
            gruplari = [ham_gruplar[k] for k in yolak_keys]
            toplam_gerekli = sum(g["gerekli"] for g in gruplari)
            toplam_saglanan = sum(g["saglanan"] for g in gruplari)
            sanal_ad = f"Yolak {yol_prefix}"
            ham_gruplar[sanal_ad] = {
                "grup": sanal_ad,
                "gerekli": toplam_gerekli,
                "saglanan": toplam_saglanan,
                "toplam": sum(g["toplam"] for g in gruplari),
                "veya": False,  # yolak içi AND
                "var_sayi": sum(g["var_sayi"] for g in gruplari),
                "sanal_yolak": True,
                "yolak_prefix": yol_prefix,
                "alt_yolak_keys": yolak_keys,
            }
            yolak_sanal_keys.append(sanal_ad)
            for k in yolak_keys:
                ham_gruplar[k]["alt"] = True

        # 2+ sanal yolak varsa üst-VEYA (≥1 yolak tam → VAR)
        if len(yolak_sanal_keys) >= 2:
            yolak_gruplari = [ham_gruplar[k] for k in yolak_sanal_keys]
            tam_olanlar = [g for g in yolak_gruplari
                           if g["saglanan"] >= g["gerekli"]
                           and g["gerekli"] > 0]
            if tam_olanlar:
                secilen = min(tam_olanlar, key=lambda g: g["gerekli"])
            else:
                secilen = max(yolak_gruplari, key=lambda g: g["saglanan"])
            prefix_listesi = [ham_gruplar[k]["yolak_prefix"]
                              for k in yolak_sanal_keys]
            yolak_birlesik = f"Yolaklar [{'∨'.join(prefix_listesi)}]"
            ham_gruplar[yolak_birlesik] = {
                "grup": yolak_birlesik,
                "gerekli": 1,
                "saglanan": 1 if tam_olanlar else 0,
                "toplam": sum(g["toplam"] for g in yolak_gruplari),
                "veya": True,
                "var_sayi": sum(g["var_sayi"] for g in yolak_gruplari),
                "secilen_yol": secilen["grup"],
                "yolak_birlesik": True,
                "alt_yolak_keys": yolak_sanal_keys,
            }
            for k in yolak_sanal_keys:
                ham_gruplar[k]["alt"] = True

        sonuc_listesi = list(ham_gruplar.values())
        gerekli_t = sum(g["gerekli"] for g in sonuc_listesi if not g.get("alt"))
        saglanan_t = sum(g["saglanan"] for g in sonuc_listesi if not g.get("alt"))
        return {
            "gerekli_toplam": gerekli_t,
            "saglanan_toplam": saglanan_t,
            "gruplar": sonuc_listesi,
        }

    def _sema_render(self, satir: dict) -> None:
        """Şema render — Tab D (DMN) + Tab G (Klasik) dispatcher."""
        self._sema_render_devre(satir)

    def _sema_render_devre(self, satir: dict) -> None:
        """Devre şeması render — Canvas üzerinde pil/ampul/kablo çizer."""
        self._sema_temizle()

        verdict = (satir.get("verdict") or "").strip()
        sartlar_json = satir.get("verdict_sartlar") or ""
        detaylar_json = satir.get("verdict_detaylar") or ""

        # DEBUG — sema render giriş
        try:
            import logging
            logging.getLogger(__name__).info(
                "SEMA RENDER: ri_id=%s, verdict=%r, "
                "sartlar_json_len=%d, ilac=%r",
                satir.get("ri_id"), verdict, len(sartlar_json),
                (satir.get("ilac") or "")[:40])
            if sartlar_json:
                logging.getLogger(__name__).info(
                    "SEMA SARTLAR JSON: %s", sartlar_json[:400])
        except Exception:
            pass

        if not verdict and not sartlar_json:
            tk.Label(self._sema_ozet,
                     text="Bu reçete için kontrol yapılmamış",
                     bg="#FAFBFC", fg="#90A4AE",
                     font=("Segoe UI", 9, "italic")).pack(pady=20)
            return

        try:
            sartlar = json.loads(sartlar_json) if sartlar_json else []
        except Exception:
            sartlar = []
        try:
            detaylar = json.loads(detaylar_json) if detaylar_json else {}
        except Exception:
            detaylar = {}

        gmat = self._sema_grup_matematigi(sartlar)
        gerekli_t = gmat["gerekli_toplam"]
        saglanan_t = gmat["saglanan_toplam"]

        # Üst banda (devre + kart için ortak)
        self._sema_ust_banda_yaz(satir, sartlar, detaylar, verdict,
                                  gerekli_t, saglanan_t)

        if not sartlar:
            return

        # Aktif sekmeler: Tab D (DMN Karar Modeli) + Tab G (Klasik Akım).
        # Tab A/B/C/E/F kullanıcı tarafından kaldırıldı (snapshot: 3cd6b33).
        self.root.update_idletasks()  # canvas genişliğini al
        # DMN Karar Modeli (Tab D, OMG/HL7 FHIR CPG standardı, pilot: YOAK)
        try:
            self._dmn_ciz_canvas(sartlar, detaylar=detaylar,
                                  verdict=verdict, satir=satir)
        except Exception:
            import logging
            logging.getLogger(__name__).exception(
                'DMN Karar Modeli renderer hatası')
        # Klasik Akım Şeması — ampul + dikey paralel (Tab G, sade görsel)
        try:
            self._klasik_ciz_canvas(sartlar, detaylar=detaylar,
                                     verdict=verdict, satir=satir)
        except Exception:
            import logging
            logging.getLogger(__name__).exception(
                'Klasik Akım renderer hatası')

        # Boş alanlara reçete/rapor açıklamalarını yerleştir (her iki canvas)
        try:
            for _canvas in (getattr(self, '_dmn_canvas', None),
                            getattr(self, '_klasik_canvas', None)):
                if _canvas is not None:
                    self._sema_aciklama_bloku_ciz(_canvas, satir)
        except Exception:
            import logging
            logging.getLogger(__name__).exception(
                'Açıklama bloğu çizim hatası')

    def _sema_aciklama_bloku_ciz(self, canvas, satir: dict) -> None:
        """Canvas'ın boş alanına reçete/rapor açıklama + teşhislerini yerleştir.

        Strateji:
          • İçeriğin bbox'ı alınır.
          • Canvas widget'ı yeterince genişse → SAĞA sığdır (içeriğin yanına).
          • Değilse → ALTA sığdır (içeriğin altına).
          • Metin: her başlık (📄/🩺) sarı kutu içinde, içerik koyu gri.
          • Canvas scrollregion bbox'ı güncellenir ki kayabilsin.
        """
        try:
            canvas.update_idletasks()
            bbox = canvas.bbox("all")
            if not bbox:
                return
            x0, y0, x1, y1 = bbox

            # Açıklama parçalarını topla
            parcalar = []
            def _ekle(baslik: str, icerik: str, vurgu: str = ""):
                if not icerik:
                    return
                txt = icerik.strip()
                if not txt:
                    return
                parcalar.append((baslik, txt, vurgu))

            # Reçete yazan branşı (üstte — reçeteyle birlikte gruplandı)
            _ekle("👨‍⚕ Reçete Yazan",
                   str(satir.get("brans") or ""), "#0D47A1")
            _ekle("📄 Reçete Açıklaması",
                   str(satir.get("rec_ack") or ""), "#0D47A1")
            # Rapor yazan doktor branşı — heyet üyesi varsa heyet listesi,
            # yoksa tek branş fallback, hiçbiri yoksa açıklayıcı placeholder.
            # (HASAN KILIÇ 2X11WU7 / kullanıcı talebi 2026-05-17: bu alanı sağ
            # info kartında göster.)
            try:
                _rap_yazan_str = ""
                _rap_kod = (satir.get("rap_kod") or "").strip()
                if _rap_kod:
                    _heyet = self._sema_heyet_brans_listesi(
                        satir.get("rapor_ana_id"))
                    if _heyet:
                        _rap_yazan_str = " · ".join(_heyet)
                    else:
                        _tek = (satir.get("rapor_doktor_brans") or "").strip()
                        if _tek:
                            _rap_yazan_str = _tek
                        else:
                            _rap_yazan_str = "(branş bilgisi DB'de yok)"
                if _rap_yazan_str:
                    _ekle("👨‍⚕ Rapor Yazan", _rap_yazan_str, "#1B5E20")
            except Exception:
                pass
            _ekle("📄 Rapor Açıklaması",
                   str(satir.get("rap_ack") or ""), "#1B5E20")
            _ekle("🩺 Reçete Teşhisi",
                   str(satir.get("rec_tesh") or ""), "#6A1B9A")
            _ekle("🩺 Rapor Teşhisi",
                   str(satir.get("rap_tesh") or ""), "#4A148C")
            _ekle("💊 Etken Madde",
                   str(satir.get("etkin") or ""), "#37474F")
            _ekle("🔢 Reçete Doz",
                   str(satir.get("rec_doz") or ""), "#37474F")
            _ekle("🔢 Rapor Doz",
                   str(satir.get("rap_doz") or ""), "#37474F")
            _ekle("ℹ Uyarı Kodu",
                   str(satir.get("uyari") or ""), "#E65100")
            # SUT Kuralı (mevzuat lafzı) — Medula Msj DEĞİL!
            # Medula Msj = ilaç bilgi penceresi sistem mesajı (provizyon yanıtı).
            # SUT Kuralı = SGK SUT mevzuat madde lafzı (resmî kaynak).
            # Bu panel atomik şema → SUT karşılığını gösterir.
            try:
                from recete_kontrol.sut_metni_kayit import sut_metni_getir
                _sut_metni = sut_metni_getir(satir.get("verdict_kategori"))
            except Exception:
                _sut_metni = None
            if _sut_metni:
                _ekle("📖 SUT Kuralı", _sut_metni, "#1A237E")
            else:
                # Fallback: kategoriye SUT lafzı kayıtlı değilse Medula Msj göster
                # (henüz SUT kayıt sistemine eklenmemiş ilaç grupları için)
                _ekle("ℹ Medula Msj",
                       str(satir.get("medula_msj") or ""), "#BF360C")

            if not parcalar:
                return

            # Canvas widget genişliği
            try:
                cw = max(canvas.winfo_width(), 200)
            except Exception:
                cw = 1000
            try:
                ch = max(canvas.winfo_height(), 200)
            except Exception:
                ch = 600

            icerik_w = x1 - x0
            icerik_h = y1 - y0

            # Açıklama bloğu için hedef genişlik (sağ taraf veya alt)
            BLOK_GENISLIK = 360
            BOSLUK = 20

            # Yerleştirme stratejisi
            if icerik_w + BOSLUK + BLOK_GENISLIK <= cw:
                # SAĞA — şemanın yanı
                ax = x1 + BOSLUK
                ay = y0
            else:
                # ALTA — şemanın altı
                ax = x0
                ay = y1 + BOSLUK
                # Daha geniş kullanılabilir: canvas genişliği kadar
                BLOK_GENISLIK = max(BLOK_GENISLIK, min(cw - 30, icerik_w))

            # Çerçeve (sarı arka plan)
            wrap_pad = 8
            satir_yuk = 0
            sat_y = ay + wrap_pad + 4

            # Önce metinleri yerleştir ve toplam yüksekliği bul
            text_items = []
            for baslik, icerik, vurgu in parcalar:
                t_baslik = canvas.create_text(
                    ax + wrap_pad, sat_y, anchor="nw",
                    text=baslik, fill=vurgu or "#37474F",
                    font=("Segoe UI", 9, "bold"),
                    width=BLOK_GENISLIK - 2 * wrap_pad,
                    tags=("klasik", "sema_aciklama"))
                bb = canvas.bbox(t_baslik) or (0, 0, 0, sat_y + 16)
                sat_y = bb[3] + 2
                t_icerik = canvas.create_text(
                    ax + wrap_pad + 8, sat_y, anchor="nw",
                    text=icerik, fill="#263238",
                    font=("Segoe UI", 9),
                    width=BLOK_GENISLIK - 2 * wrap_pad - 8,
                    tags=("klasik", "sema_aciklama"))
                bb2 = canvas.bbox(t_icerik) or (0, 0, 0, sat_y + 16)
                sat_y = bb2[3] + 8
                text_items.append((t_baslik, t_icerik))

            blok_h = max(40, sat_y - ay - wrap_pad)

            # Sarı arka plan kutusu (metinlerin altına gelmesi için ilk önce
            # ekleyip sonra lower yapıyoruz)
            bg_rect = canvas.create_rectangle(
                ax, ay, ax + BLOK_GENISLIK, ay + blok_h,
                fill="#FFFDE7", outline="#FFB300", width=1,
                tags=("klasik", "sema_aciklama_bg"))
            # Arkaya çek
            try:
                canvas.tag_lower(bg_rect)
                # text item'ları üste getir
                for tb, ti in text_items:
                    canvas.tag_raise(tb)
                    canvas.tag_raise(ti)
            except Exception:
                pass

            # Scrollregion güncelle
            try:
                new_bbox = canvas.bbox("all")
                if new_bbox:
                    canvas.configure(scrollregion=new_bbox)
            except Exception:
                pass
        except Exception:
            import logging
            logging.getLogger(__name__).exception(
                '_sema_aciklama_bloku_ciz: render hatası')

    def _sema_ust_banda_yaz(self, satir: dict, sartlar: list, detaylar: dict,
                             verdict: str, gerekli_t: int, saglanan_t: int) -> None:
        """Üst özet bandını yatay tek satır olarak yazar (alt panel için)."""
        alt_dal = (detaylar.get("alt_dal") or "").strip()
        endikasyon = (detaylar.get("endikasyon") or "").strip()
        sut_kurali = (satir.get("verdict_sut") or "").strip()

        yolak_text = ""
        if alt_dal:
            if "D-1" in alt_dal:
                yolak_text = f"📍 {alt_dal} AF"
            elif "D-2" in alt_dal:
                yolak_text = f"📍 {alt_dal} DVT/PE"
            else:
                yolak_text = f"📍 {alt_dal}"
        elif sut_kurali:
            yolak_text = f"📍 {sut_kurali[:30]}"

        # Yatay tek satır: yolak | sayım (büyük) | sonuç badge | ilaç
        sayim_text = f"  {saglanan_t} / {gerekli_t}  ŞART KARŞILANIYOR  "
        oran = (saglanan_t / gerekli_t) if gerekli_t else 0
        if oran >= 0.99:
            sayim_fg, sayim_bg = "#1B5E20", "#C8E6C9"
        elif oran >= 0.5:
            sayim_fg, sayim_bg = "#E65100", "#FFE0B2"
        else:
            sayim_fg, sayim_bg = "#B71C1C", "#FFCDD2"
        renk_fg, renk_bg = self._SEMA_SONUC_RENK.get(
            verdict.upper(), ("#37474F", "#ECEFF1"))

        if yolak_text:
            tk.Label(self._sema_ozet, text=yolak_text,
                     bg="#FAFBFC", fg="#1565C0",
                     font=("Segoe UI", 10, "bold")
                     ).pack(side="left", padx=(8, 12), pady=8)
        tk.Label(self._sema_ozet, text=sayim_text,
                 bg=sayim_bg, fg=sayim_fg,
                 font=("Segoe UI", 11, "bold")
                 ).pack(side="left", padx=4, pady=8)
        tk.Label(self._sema_ozet,
                 text=f" ✓{sum(1 for s in sartlar if s.get('durum')=='var')}"
                      f"  ✗{sum(1 for s in sartlar if s.get('durum')=='yok')}"
                      f"  ?{sum(1 for s in sartlar if s.get('durum')=='kontrol_edilemedi')} ",
                 bg="#FAFBFC", fg="#455A64",
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=8, pady=8)
        tk.Label(self._sema_ozet, text=f"  {verdict or '—'}  ",
                 bg=renk_bg, fg=renk_fg,
                 font=("Segoe UI", 10, "bold")).pack(side="right", padx=8, pady=8)
        if endikasyon:
            tk.Label(self._sema_ozet, text=f"({endikasyon})",
                     bg="#FAFBFC", fg="#455A64",
                     font=("Segoe UI", 9)).pack(side="left", padx=4, pady=8)
        ilac = (satir.get("ilac") or "")[:30]
        if ilac:
            tk.Label(self._sema_ozet, text=ilac,
                     bg="#FAFBFC", fg="#90A4AE",
                     font=("Segoe UI", 8)).pack(side="right", padx=8, pady=8)

    def _ust_veya_baslik_bul(self, ga: str, cift_b: str,
                              ust_veya_ciftleri: list) -> str:
        """Üst-VEYA çiftine kısa görsel başlık üret.

        Örnekler:
          Varfarin (a) ∨ Varfarin (b) → '(a) ∨ (b)'
          Varfarin yolu ∨ İstisna grubu → 'Varfarin ∨ İstisna'
          SK ilk 24 ∨ 24 ay sonrası → 'SK ilk 24ay ∨ sonrası'
        """
        a_pure = (ga or '').replace('[pasif] ', '').strip()
        b_pure = (cift_b or '').replace('[pasif] ', '').strip()
        # Bilinen kalıplara göre kısa başlık
        if 'Varfarin yolu (a)' in a_pure and 'Varfarin yolu (b)' in b_pure:
            return '(a) ∨ (b)'
        if 'Varfarin yolu' in a_pure and 'İstisna grubu' in b_pure:
            return 'Varfarin ∨ İstisna'
        if 'SK raporu — ilk 24' in a_pure and '24 ay sonrası' in b_pure:
            return 'SK ilk 24ay ∨ sonrası'
        # Fallback: ilk 18 karakter ∨ ikinci ilk 18 karakter
        a_short = a_pure[:18].rstrip(' —[')
        b_short = b_pure[:18].rstrip(' —[')
        return f'{a_short} ∨ {b_short}'



